export const flashcards: Flashcard[] = [
  // ========== CARDIOLOGIA ==========
  { id: "fc-cardio-01", front: "Qual o tratamento de escolha para FV/TV sem pulso?", back: "Desfibrilação imediata (200J bifásico ou 360J monofásico) + RCP + Adrenalina 1mg IV a cada 3-5min + Amiodarona 300mg IV (1ª dose) → 150mg (2ª dose).", category: "cardiologia", tags: ["pcr", "fv", "desfibrilação"] },
  { id: "fc-cardio-02", front: "Critérios diagnósticos de IAMCSST no ECG?", back: "Supra de ST ≥ 1mm em 2 derivações contíguas (≥ 2mm em V2-V3 em homens ≥ 40a, ≥ 1.5mm em mulheres). BRE novo com clínica compatível. Supra em aVR + infra difuso = lesão de tronco.", category: "cardiologia", tags: ["iam", "ecg", "supra"] },
  { id: "fc-cardio-03", front: "Qual a classificação de Killip no IAM?", back: "I: sem IC (mortalidade 6%)\nII: estertores basais, B3, turgência jugular (17%)\nIII: EAP franco (38%)\nIV: choque cardiogênico (81%)", category: "cardiologia", tags: ["iam", "killip", "classificação"] },
  { id: "fc-cardio-04", front: "Contraindicações absolutas à trombólise no IAM?", back: "AVC hemorrágico prévio, AVC isquêmico < 3 meses, neoplasia intracraniana, sangramento ativo (exceto menstruação), dissecção de aorta, trauma facial/craniano < 3 meses.", category: "cardiologia", tags: ["iam", "trombólise", "contraindicação"] },
  { id: "fc-cardio-05", front: "Qual a tríade de Beck no tamponamento cardíaco?", back: "1. Hipotensão arterial\n2. Turgência jugular (↑PVC)\n3. Hipofonese de bulhas\n\nPulso paradoxal (queda > 10mmHg da PAS na inspiração). Diagnóstico: ECO → líquido pericárdico + colapso de câmaras direitas.", category: "cardiologia", tags: ["tamponamento", "beck", "pericárdio"] },
  { id: "fc-cardio-06", front: "Diferença entre FA e Flutter no ECG?", back: "FA: ausência de ondas P, ritmo irregularmente irregular, ondas f.\nFlutter: ondas F em 'dente de serra' (DII/DIII/aVF), frequência atrial ~300bpm, condução geralmente 2:1 (FC ~150bpm), ritmo regular.", category: "cardiologia", tags: ["fa", "flutter", "arritmia"] },
  { id: "fc-cardio-07", front: "Quando usar betabloqueador vs. verapamil na taquicardia supraventricular?", back: "Ambos para controle de FC. Verapamil é CONTRAINDICADO em: FA pré-excitada (WPW), IC com FE reduzida, uso concomitante de betabloqueador IV. Betabloqueador: preferir em IC (carvedilol, bisoprolol, metoprolol).", category: "cardiologia", tags: ["tsv", "betabloqueador", "verapamil"] },
  { id: "fc-cardio-08", front: "Qual a diferença entre Insuficiência Cardíaca HFrEF e HFpEF?", back: "HFrEF (FE ≤ 40%): dilatação ventricular, tratamento com IECA/BRA + BB + espironolactona + SGLT2i + sacubitril/valsartana.\nHFpEF (FE ≥ 50%): hipertrofia, disfunção diastólica. Tratar congestão (diuréticos) + comorbidades. SGLT2i tem benefício.", category: "cardiologia", tags: ["ic", "fração ejeção", "tratamento"] },
  
  // ========== PNEUMOLOGIA ==========
  { id: "fc-pneumo-01", front: "Critérios de Light para diferenciação de exsudato vs transudato?", back: "EXSUDATO se qualquer um:\n• Proteína pleural/sérica > 0.5\n• LDH pleural/sérica > 0.6\n• LDH pleural > 2/3 do limite superior normal sérico\n\nTransudato: IC, cirrose, síndrome nefrótica.", category: "pneumologia", tags: ["derrame pleural", "light", "exsudato"] },
  { id: "fc-pneumo-02", front: "Classificação da DPOC (GOLD) por espirometria?", back: "Pós-broncodilatador VEF1/CVF < 0.7:\nGOLD 1 (leve): VEF1 ≥ 80%\nGOLD 2 (moderada): 50-79%\nGOLD 3 (grave): 30-49%\nGOLD 4 (muito grave): < 30%\n\nClassificação ABE por sintomas + exacerbações.", category: "pneumologia", tags: ["dpoc", "gold", "espirometria"] },
  { id: "fc-pneumo-03", front: "Tratamento do pneumotórax hipertensivo?", back: "1. Diagnóstico CLÍNICO (não esperar RX!)\n2. Descompressão imediata: agulha 14G no 2º EIC linha hemiclavicular\n3. Seguido de drenagem torácica em selo d'água (5º EIC linha axilar média)\n\nSinais: desvio traqueal, ausência de MV, timpanismo, hipotensão.", category: "pneumologia", tags: ["pneumotórax", "drenagem", "emergência"] },
  { id: "fc-pneumo-04", front: "Indicações de VNI na insuficiência respiratória aguda?", back: "Indicações com forte evidência:\n• DPOC exacerbada com acidose (pH < 7.35)\n• EAP cardiogênico\n• Imunossuprimidos com IR\n• Pós-extubação em pacientes de risco\n\nContraindicações: rebaixamento de consciência, vômitos, PCR, trauma facial.", category: "pneumologia", tags: ["vni", "insuficiência respiratória", "cpap"] },
  { id: "fc-pneumo-05", front: "Qual a diferença entre SDRA leve, moderada e grave?", back: "Classificação de Berlim (P/F com PEEP ≥ 5):\nLeve: P/F 200-300 (mortalidade ~27%)\nModerada: P/F 100-200 (mortalidade ~32%)\nGrave: P/F < 100 (mortalidade ~45%)\n\nTratamento: VM protetora (VT 6ml/kg, Pplatô ≤ 30, PEEP alta, prona se P/F < 150).", category: "pneumologia", tags: ["sdra", "berlim", "vm protetora"] },
  { id: "fc-pneumo-06", front: "Parâmetros da ventilação mecânica protetora?", back: "• VT: 6 ml/kg de peso predito\n• Pressão de platô ≤ 30 cmH₂O\n• Driving pressure ≤ 15 cmH₂O\n• PEEP: tabela PEEP/FiO₂\n• FR: ajustar para pH > 7.20\n• FiO₂: menor possível para SpO₂ 92-96%", category: "pneumologia", tags: ["vm", "protetora", "sdra"] },

  // ========== NEUROLOGIA ==========
  { id: "fc-neuro-01", front: "Qual a escala de NIHSS e quando usar?", back: "National Institutes of Health Stroke Scale: 0-42 pontos.\nAvalia: consciência, olhar, campo visual, paralisia facial, força MMSS/MMII, ataxia, sensibilidade, linguagem, disartria, extinção.\n\nUsar em TODO AVC para definir gravidade e indicação de trombólise/trombectomia.", category: "neurologia", tags: ["avc", "nihss", "escala"] },
  { id: "fc-neuro-02", front: "Janela terapêutica para trombólise e trombectomia no AVC isquêmico?", back: "Trombólise IV (alteplase 0.9mg/kg): até 4.5h\nTrombectomia mecânica: até 24h (seleção por perfusão — mismatch penumbra/core)\n\nAlteplase: 10% bolus + 90% em 1h. Dose máx: 90mg.\nTenecteplase (0.25mg/kg): alternativa em bolus único.", category: "neurologia", tags: ["avc", "trombólise", "trombectomia"] },
  { id: "fc-neuro-03", front: "Tratamento do Status Epiléptico — sequência?", back: "1º (0-5min): ABC + Diazepam 10mg IV ou Midazolam 10mg IM\n2º (5-20min): Fenitoína 20mg/kg IV (em SF, 50mg/min) ou Valproato 40mg/kg IV\n3º (20-40min): Dose adicional de fenitoína 5-10mg/kg ou fenobarbital 20mg/kg\n4º (>40min): SE refratário → Midazolam, Propofol ou Tiopental em infusão contínua + IOT + EEG.", category: "neurologia", tags: ["status epiléptico", "convulsão", "antiepiléptico"] },
  { id: "fc-neuro-04", front: "Como diferenciar AVC isquêmico de hemorrágico clinicamente?", back: "Não é possível com certeza — TC é obrigatória!\nSugestivo de hemorrágico: cefaleia intensa, vômitos, rebaixamento precoce, hipertensão grave.\nSugestivo de isquêmico: déficit focal abrupto sem cefaleia intensa.\n\nRegra: TODA suspeita de AVC → TC sem contraste IMEDIATA.", category: "neurologia", tags: ["avc", "diagnóstico diferencial", "tc"] },
  { id: "fc-neuro-05", front: "Critérios diagnósticos de morte encefálica no Brasil?", back: "CFM 2.173/2017:\n1. Pré-requisitos: causa conhecida, T > 35°C, sem drogas depressoras, sem DHE grave\n2. Dois exames clínicos (intervalos por idade) por médicos diferentes\n3. Teste de apneia (pCO₂ > 55 mmHg sem drive respiratório)\n4. Exame complementar: angiografia, EEG, DTC ou cintilografia", category: "neurologia", tags: ["morte encefálica", "critérios", "apneia"] },

  // ========== INFECTOLOGIA ==========
  { id: "fc-infecto-01", front: "Critérios diagnósticos de sepse (Sepsis-3)?", back: "Sepse: infecção SUSPEITA ou CONFIRMADA + aumento ≥ 2 pontos no SOFA.\nChoque séptico: sepse + necessidade de vasopressor para PAM ≥ 65 + lactato > 2 mmol/L após ressuscitação volêmica adequada.\n\nqSOFA (screening): FR ≥ 22, PAS ≤ 100, alteração mental.", category: "infectologia", tags: ["sepse", "sofa", "critérios"] },
  { id: "fc-infecto-02", front: "Antibióticos empíricos na PAC — ambulatorial vs internado?", back: "Ambulatorial sem comorbidades: Amoxicilina 500mg 8/8h\nAmbulatrial com comorbidades: Amoxicilina-clavulanato + Azitromicina ou Levofloxacino\nEnfermaria: Ceftriaxone 1g IV 12/12h + Azitromicina 500mg IV/VO\nUTI: Ceftriaxone + Azitromicina (ou Levofloxacino). Se risco MRSA: + Vancomicina.", category: "infectologia", tags: ["pneumonia", "antibiótico", "pac"] },
  { id: "fc-infecto-03", front: "Quando cobrir anaeróbios em pneumonia?", back: "Indicações: abscesso pulmonar, pneumonia aspirativa com cavitação, empiema.\nEscolhas: Clindamicina 600mg IV 6/6h, Amoxicilina-clavulanato, Metronidazol (apenas se associado a outro ATB, não cobre aeróbios).\n\nPneumonia aspirativa SEM cavitação: Amoxicilina-clavulanato é suficiente.", category: "infectologia", tags: ["anaeróbio", "aspirativa", "abscesso"] },
  { id: "fc-infecto-04", front: "Esquema RIPE para tuberculose — doses e duração?", back: "Fase intensiva (2 meses): RHZE\n• Rifampicina (R) 150mg\n• Isoniazida (H) 75mg\n• Pirazinamida (Z) 400mg\n• Etambutol (E) 275mg\n(Dose fixa combinada por peso)\n\nFase manutenção (4 meses): RH\nTotal: 6 meses (meningite TB: 12 meses).", category: "infectologia", tags: ["tuberculose", "ripe", "tratamento"] },
  { id: "fc-infecto-05", front: "Classificação de dengue e sinais de alarme?", back: "Dengue sem sinais de alarme → Grupo A (hidratação oral)\nCom sinais de alarme → Grupo C (hidratação IV)\nDengue grave → Grupo D (expansão rápida)\n\nSinais de alarme: dor abdominal intensa, vômitos persistentes, acúmulo de líquidos, sangramento mucosa, letargia, hepatomegalia, ↑Ht com ↓plaquetas.", category: "infectologia", tags: ["dengue", "alarme", "classificação"] },

  // ========== NEFROLOGIA ==========
  { id: "fc-nefro-01", front: "Indicações de diálise de urgência (mnemônico AEIOU)?", back: "A — Acidose metabólica grave refratária (pH < 7.1)\nE — Eletrólitos: hipercalemia refratária (K > 6.5)\nI — Intoxicação (metanol, etilenoglicol, lítio, salicilato)\nO — Overload (hipervolemia refratária)\nU — Uremia sintomática (encefalopatia, pericardite, sangramento)", category: "nefrologia", tags: ["diálise", "urgência", "aeiou"] },
  { id: "fc-nefro-02", front: "Como diferenciar IRA pré-renal de renal (NTA)?", back: "Pré-renal: Na urinário < 20, FENa < 1%, osmolaridade urinária > 500, cilindros hialinos.\nNTA (renal): Na urinário > 40, FENa > 2%, osmolaridade urinária < 350, cilindros granulosos ('muddy brown').\n\nFENa = (NaU × CrP) / (NaP × CrU) × 100", category: "nefrologia", tags: ["ira", "pré-renal", "nta"] },
  { id: "fc-nefro-03", front: "Classificação KDIGO de lesão renal aguda?", back: "Estágio 1: Cr ↑ 1.5-1.9x basal ou ↑ ≥ 0.3mg/dL em 48h ou diurese < 0.5ml/kg/h por 6-12h\nEstágio 2: Cr ↑ 2.0-2.9x basal ou diurese < 0.5ml/kg/h por ≥ 12h\nEstágio 3: Cr ↑ ≥ 3x basal ou Cr ≥ 4mg/dL ou diálise ou diurese < 0.3ml/kg/h por ≥ 24h ou anúria ≥ 12h", category: "nefrologia", tags: ["kdigo", "ira", "classificação"] },

  // ========== ENDOCRINOLOGIA ==========
  { id: "fc-endo-01", front: "Diagnóstico e tratamento da cetoacidose diabética (CAD)?", back: "Diagnóstico: glicemia > 250, pH < 7.3, HCO₃ < 18, cetonemia/cetonúria, AG aumentado.\n\nTratamento:\n1. SF 0.9% 1-1.5L na 1ª hora\n2. Insulina regular 0.1 UI/kg/h IV\n3. Repor K+ se < 5.3 (ANTES da insulina se K < 3.3)\n4. Bicarbonato APENAS se pH < 6.9", category: "endocrinologia", tags: ["cad", "diabetes", "insulina"] },
  { id: "fc-endo-02", front: "Diferença entre CAD e Estado Hiperglicêmico Hiperosmolar (EHH)?", back: "CAD: DM1, glicemia 250-600, pH < 7.3, cetose +++, AG ↑, osmolaridade variável.\nEHH: DM2 idosos, glicemia > 600, pH > 7.3, cetose leve/ausente, osmolaridade > 320 mOsm/kg.\n\nEHH: desidratação muito mais intensa. Volume: até 6-9L nas primeiras 24h. Insulina em dose mais baixa.", category: "endocrinologia", tags: ["ehh", "cad", "diferencial"] },
  { id: "fc-endo-03", front: "Critérios diagnósticos de tireotoxicose/tempestade tireoidiana?", back: "Score de Burch-Wartofsky ≥ 45 = altamente sugestivo:\nFebre, taquicardia, IC, disfunção GI, alteração neurológica.\n\nTratamento:\n1. PTU 200mg VO 4/4h (bloqueia síntese + conversão T4→T3)\n2. Iodo (Lugol) 1h APÓS PTU\n3. Propranolol IV/VO\n4. Hidrocortisona 100mg IV 8/8h\n5. Suporte: resfriar, hidratar", category: "endocrinologia", tags: ["tireotoxicose", "tempestade", "ptu"] },

  // ========== GASTROENTEROLOGIA ==========
  { id: "fc-gastro-01", front: "Classificação de Child-Pugh na cirrose — parâmetros?", back: "5 parâmetros (1-3 pontos cada):\n• Bilirrubina\n• Albumina\n• INR/TP\n• Ascite\n• Encefalopatia hepática\n\nChild A: 5-6 pts (sobrevida 100% em 1 ano)\nChild B: 7-9 pts (81%)\nChild C: 10-15 pts (45%)", category: "gastroenterologia", tags: ["cirrose", "child-pugh", "prognóstico"] },
  { id: "fc-gastro-02", front: "Conduta na hemorragia digestiva alta varicosa?", back: "1. Estabilizar: acesso calibroso, cristalóide, transfusão (alvo Hb 7-8)\n2. Octreotida/Terlipressina IV (antes mesmo da EDA)\n3. Ceftriaxone 1g/dia (profilaxia PBE)\n4. EDA em < 12h: ligadura elástica\n5. Se falha: TIPS ou balão de Sengstaken-Blakemore (temporário)", category: "gastroenterologia", tags: ["hda", "varicosa", "octreotida"] },
  { id: "fc-gastro-03", front: "Diagnóstico e tratamento da peritonite bacteriana espontânea (PBE)?", back: "Diagnóstico: paracentese com PMN ≥ 250/mm³ no líquido ascítico.\nCultura: monobacteriana (E. coli, Klebsiella, pneumococo).\n\nTratamento: Ceftriaxone 2g/dia por 5 dias + Albumina 1.5g/kg no D1 e 1g/kg no D3 (reduz mortalidade de 30% para 10%).\nProfilaxia secundária: Norfloxacino 400mg/dia.", category: "gastroenterologia", tags: ["pbe", "ascite", "paracentese"] },

  // ========== HEMATOLOGIA ==========
  { id: "fc-hemato-01", front: "Quando transfundir concentrado de hemácias?", back: "• Hb < 7 g/dL: maioria dos pacientes estáveis (restritiva)\n• Hb < 8 g/dL: cardiopatas, cirurgia cardíaca, sepse precoce\n• Hb < 9-10 g/dL: SCA com instabilidade\n\nSempre avaliar CLÍNICA (taquicardia, hipotensão, dispneia) além do valor numérico.", category: "hematologia", tags: ["transfusão", "hemácias", "threshold"] },
  { id: "fc-hemato-02", front: "Diferença entre PTT e SHU?", back: "PTT: ADAMTS13 < 10%, pêntade (trombocitopenia, anemia hemolítica microangiopática, febre, alteração neurológica, IRA). Tratamento: plasmaférese.\nSHU: pós-diarreia (E. coli O157:H7), tríade (trombocitopenia, AHMA, IRA). Crianças. Tratamento: suporte. Atípico: eculizumabe.", category: "hematologia", tags: ["ptt", "shu", "microangiopatia"] },
  { id: "fc-hemato-03", front: "Protocolo de transfusão maciça — quando ativar e proporção?", back: "Ativar se: perda ≥ 1 volemia em 24h, > 10 CH em 24h, sangramento incontrolável.\nProporção: CH:PFC:Plaquetas = 1:1:1\nÁcido tranexâmico 1g IV em < 3h do trauma (CRASH-2).\nFibrinogênio: crioprecipitado se < 150mg/dL.", category: "hematologia", tags: ["transfusão maciça", "trauma", "1:1:1"] },

  // ========== EMERGÊNCIA ==========
  { id: "fc-emerg-01", front: "ABCDE do trauma — o que cada letra significa?", back: "A: Airway + proteção cervical\nB: Breathing (ventilação)\nC: Circulation (controle de hemorragia)\nD: Disability (neurológico — Glasgow, pupilas)\nE: Exposure (exposição com controle de hipotermia)\n\nSempre na ORDEM. Tratar o que encontrar antes de avançar.", category: "emergencia", tags: ["atls", "trauma", "abcde"] },
  { id: "fc-emerg-02", front: "Qual a sequência rápida de intubação (SRI)?", back: "1. Preparação (material, drogas, plano B)\n2. Pré-oxigenação 3-5min (SpO₂ 100%)\n3. Pré-tratamento (fentanil 1-2mcg/kg se HIC/reatividade)\n4. Paralisia + Indução:\n   • Etomidato 0.3mg/kg ou Quetamina 1-2mg/kg\n   • Succinilcolina 1.5mg/kg ou Rocurônio 1.2mg/kg\n5. Posicionar e intubar\n6. Confirmar (capnografia!)", category: "emergencia", tags: ["iot", "sri", "intubação"] },
  { id: "fc-emerg-03", front: "Drogas e doses na anafilaxia?", back: "1ª LINHA: Adrenalina 0.3-0.5mg IM (1:1000) na face anterolateral da coxa. Repetir a cada 5-15min se necessário.\n\n2ª linha:\n• Difenidramina 25-50mg IV\n• Ranitidina 50mg IV\n• Metilprednisolona 125mg IV\n• SF 0.9% 1-2L rápido se hipotensão\n• Salbutamol NBI se broncoespasmo", category: "emergencia", tags: ["anafilaxia", "adrenalina", "alergia"] },
  { id: "fc-emerg-04", front: "Como manejar a via aérea difícil (plano B/C/D)?", back: "Plano A: Laringoscopia direta/videolaringoscopia\nPlano B: Dispositivo supraglótico (máscara laríngea)\nPlano C: Ventilação com máscara + guedel (voltar ao básico)\nPlano D: Cricotireoidostomia cirúrgica ('can't intubate, can't oxygenate')\n\nNUNCA mais de 3 tentativas de laringoscopia sem oxigenar.", category: "emergencia", tags: ["via aérea difícil", "cricotireoidostomia", "supraglótico"] },

  // ========== PEDIATRIA ==========
  { id: "fc-ped-01", front: "Classificação da desidratação em crianças e reposição?", back: "Leve (< 5%): mucosas secas, sede. Plano A: TRO domiciliar.\nModerada (5-10%): olhos encovados, turgor reduzido, taquicardia. Plano B: TRO supervisionada 4h.\nGrave (> 10%): letargia/coma, pulsos finos, tempo enchimento > 3s. Plano C: SF 20ml/kg em 20min, repetir até 3x.", category: "pediatria", tags: ["desidratação", "tro", "reposição"] },
  { id: "fc-ped-02", front: "Cálculo de hidratação de manutenção IV em crianças (Holliday-Segar)?", back: "• Até 10 kg: 100 ml/kg/dia\n• 10-20 kg: 1000 + 50 ml/kg acima de 10\n• > 20 kg: 1500 + 20 ml/kg acima de 20\n\nExemplo: criança de 25kg = 1500 + (5×20) = 1600 ml/dia = ~67 ml/h\nSolução: SG5% + NaCl 20% (3ml/500ml) + KCl 10% (5ml/500ml).", category: "pediatria", tags: ["hidratação", "holliday-segar", "manutenção"] },
  { id: "fc-ped-03", front: "Dose de adrenalina na PCR pediátrica?", back: "Adrenalina: 0.01 mg/kg (0.1 ml/kg da solução 1:10.000) IV/IO\nDose máxima: 1mg\nRepetir a cada 3-5 minutos\n\nCompressões: 100-120/min\nRelação: 15:2 (2 socorristas) ou 30:2 (1 socorrista)\nProfundidade: 1/3 do diâmetro AP do tórax.", category: "pediatria", tags: ["pcr", "pediátrica", "adrenalina"] },
  { id: "fc-ped-04", front: "Critérios de internação na bronquiolite (lactentes)?", back: "• < 3 meses ou prematuros < 6 meses\n• SpO₂ < 92% em ar ambiente\n• Desconforto respiratório moderado/grave (tiragem, batimento de asa)\n• Apneia\n• Incapacidade de alimentação\n• Comorbidades: cardiopatia, doença pulmonar crônica, imunodeficiência\n\nTratamento: O₂ + hidratação. NÃO usar broncodilatador/corticóide de rotina.", category: "pediatria", tags: ["bronquiolite", "lactente", "internação"] },

  // ========== OBSTETRÍCIA ==========
  { id: "fc-obst-01", front: "Diagnóstico e tratamento da pré-eclâmpsia grave?", back: "Diagnóstico: PA ≥ 160/110 + proteinúria ≥ 300mg/24h (ou relação P/C ≥ 0.3) OU sinais de gravidade (cefaleia, epigastralgia, trombocitopenia < 100.000, Cr > 1.1, TGO/TGP > 2x).\n\nTratamento:\n1. Sulfato de Magnésio (Zuspan: 4g IV bolus + 1-2g/h IV)\n2. Anti-hipertensivo: Nifedipina VO ou Hidralazina IV\n3. Resolução da gestação (> 34 sem ou se instável).", category: "obstetricia", tags: ["pré-eclâmpsia", "magnésio", "zuspan"] },
  { id: "fc-obst-02", front: "Sinais de intoxicação por sulfato de magnésio e antídoto?", back: "Monitorar a cada 1-2h:\n• Reflexo patelar abolido (primeiro sinal — 10mg/dL)\n• FR < 16 irpm (15mg/dL)\n• Parada respiratória (> 15mg/dL)\n• Parada cardíaca (> 25mg/dL)\n\nAntídoto: Gluconato de Cálcio 10% — 10ml IV lento (1g em 3-5 min).\nManter diurese ≥ 25ml/h (excreção é renal).", category: "obstetricia", tags: ["magnésio", "intoxicação", "gluconato cálcio"] },
  { id: "fc-obst-03", front: "Classificação de hemorragia pós-parto e tratamento escalonado?", back: "HPP: perda ≥ 500ml (vaginal) ou ≥ 1000ml (cesárea).\n\n4 T's (causas): Tônus (70%), Trauma, Tecido, Trombina.\n\nEscalonamento:\n1. Massagem uterina + Ocitocina 20-40UI em SF\n2. Misoprostol 800mcg retal + Ác. Tranexâmico 1g IV\n3. Balão de Bakri\n4. Sutura de B-Lynch\n5. Histerectomia (último recurso)", category: "obstetricia", tags: ["hpp", "hemorragia", "4ts"] },

  // ========== CIRURGIA ==========
  { id: "fc-cir-01", front: "Indicações de laparotomia exploradora no trauma abdominal?", back: "Absolutas:\n• Instabilidade hemodinâmica com FAST positivo\n• Peritonite difusa\n• Evisceração\n• Pneumoperitônio\n• Lesão diafragmática\n• FAB transabdominal\n\nRelativas: sangramento GI, lesão de víscera oca na TC, sangue na SNG/sonda retal.", category: "cirurgia", tags: ["laparotomia", "trauma", "abdome agudo"] },
  { id: "fc-cir-02", front: "Classificação de Hinchey para diverticulite complicada?", back: "I: abscesso pericólico (< 4cm) → ATB IV\nII: abscesso pélvico/retroperitoneal (> 4cm) → drenagem percutânea\nIII: peritonite purulenta (ruptura de abscesso) → cirurgia\nIV: peritonite fecal (perfuração livre) → cirurgia de URGÊNCIA (Hartmann)\n\nNão complicada: ATB oral + dieta líquida. Colonoscopia em 6 sem.", category: "cirurgia", tags: ["diverticulite", "hinchey", "peritonite"] },
  { id: "fc-cir-03", front: "Score de Alvarado para apendicite — critérios?", back: "Sintomas:\n• Migração da dor para FID (1 pt)\n• Anorexia (1 pt)\n• Náuseas/vômitos (1 pt)\n\nSinais:\n• Dor em FID (2 pts)\n• Descompressão brusca (1 pt)\n• Febre > 37.3°C (1 pt)\n\nLab:\n• Leucocitose > 10.000 (2 pts)\n• Desvio à esquerda (1 pt)\n\nTotal 10 pts. ≥ 7: alta probabilidade → cirurgia.", category: "cirurgia", tags: ["apendicite", "alvarado", "score"] },

  // ========== FARMACOLOGIA ==========
  { id: "fc-farma-01", front: "Antídotos de emergência — principais pares droga/antídoto?", back: "• Paracetamol → N-Acetilcisteína\n• Opióides → Naloxona\n• Benzodiazepínicos → Flumazenil\n• Organofosforados → Atropina + Pralidoxima\n• Cumarínicos (warfarina) → Vitamina K + CCP\n• Heparina → Protamina\n• Dabigatrana → Idarucizumabe\n• Digitálicos → Anticorpos anti-digoxina\n• Metanol/Etilenoglicol → Fomepizol ou Etanol + Diálise", category: "farmacologia", tags: ["antídoto", "intoxicação", "emergência"] },
  { id: "fc-farma-02", front: "Quais drogas prolongam o QT e risco de Torsades?", back: "Classes/drogas que prolongam QT:\n• Antiarrítmicos: Amiodarona, Sotalol, Procainamida\n• Antibióticos: Macrolídeos, Fluoroquinolonas\n• Antipsicóticos: Haloperidol, Quetiapina\n• Antidepressivos: Tricíclicos, Citalopram\n• Outros: Ondansetrona, Metadona, Domperidona\n\nSe Torsades: Magnésio 2g IV. NUNCA Amiodarona!", category: "farmacologia", tags: ["qt longo", "torsades", "medicamentos"] },
  { id: "fc-farma-03", front: "Drogas contraindicadas na gestação — categoria X?", back: "• Metotrexato\n• Warfarina (1º trimestre)\n• Misoprostol\n• Isotretinoína\n• Talidomida\n• Estatinas\n• IECA/BRA (2º e 3º trimestre)\n• Tetraciclinas\n• Finasterida\n• Ribavirina\n\nAlternativas seguras: insulina, metildopa, labetalol, penicilinas, cefalosporinas.", category: "farmacologia", tags: ["gestação", "categoria x", "contraindicação"] },

  // ========== PSIQUIATRIA ==========
  { id: "fc-psiq-01", front: "Tratamento da agitação psicomotora no PS?", back: "1º: Abordagem verbal (descalada)\n2º: Contenção química:\n• Haloperidol 5mg IM + Midazolam 5mg IM (mais usado)\n• Alternativa: Olanzapina 10mg IM (evitar com BZD)\n• Se intoxicação por estimulantes: BZD isolado (Diazepam 10mg IV)\n\n3º: Contenção mecânica (último recurso, com monitorização contínua).\nECG antes se possível (risco de QT longo com haloperidol).", category: "psiquiatria", tags: ["agitação", "contenção", "haloperidol"] },
  { id: "fc-psiq-02", front: "Síndrome Neuroléptica Maligna — diagnóstico e tratamento?", back: "Tétrade: hipertermia + rigidez muscular + alteração mental + disautonomia.\nLab: CPK muito elevada (> 1000), leucocitose, mioglobinúria.\n\nTratamento:\n1. Suspender antipsicótico\n2. Suporte (hidratação, resfriamento)\n3. Dantrolene 1-2.5mg/kg IV (relaxante muscular)\n4. Bromocriptina 2.5mg VO 8/8h\n5. Monitorar CPK, função renal (rabdomiólise)", category: "psiquiatria", tags: ["snm", "neuroléptica", "dantrolene"] },
  { id: "fc-psiq-03", front: "Avaliação de risco suicida — fatores e conduta?", back: "Fatores de alto risco: tentativa prévia, plano detalhado, acesso a meios letais, isolamento social, transtorno psiquiátrico (depressão, bipolar, esquizofrenia), abuso de substâncias, desesperança.\n\nConduta:\n1. Perguntar diretamente sobre ideação suicida\n2. Escala Columbia (C-SSRS)\n3. Restringir acesso a meios letais\n4. Internação se risco iminente\n5. Não deixar sozinho", category: "psiquiatria", tags: ["suicídio", "risco", "columbia"] },

  // ========== DERMATOLOGIA ==========
  { id: "fc-derm-01", front: "Como diferenciar celulite de erisipela?", back: "Erisipela: infecção superficial (derme superior), bordas BEM DELIMITADAS, eritema vivo, placas elevadas. Agente: Streptococcus (grupo A).\n\nCelulite: infecção profunda (derme + subcutâneo), bordas MAL DELIMITADAS, eritema difuso. Agentes: S. aureus + Streptococcus.\n\nTratamento erisipela: Penicilina Cristalina.\nCelulite: Oxacilina ou Cefalosporina 1ª geração.", category: "dermatologia", tags: ["celulite", "erisipela", "infecção"] },
  { id: "fc-derm-02", front: "Classificação de Stevens-Johnson vs Necrólise Epidérmica Tóxica (NET)?", back: "SSJ: descolamento < 10% da superfície corporal.\nOverlap SSJ/NET: 10-30%.\nNET: > 30%.\n\nCausas: medicamentos (sulfonamidas, anticonvulsivantes, AINEs, alopurinol).\nSinal de Nikolsky positivo.\n\nConduta: suspender droga causadora, UTI/CTQ, suporte (fluidos, analgesia), NÃO usar corticoides de rotina. SCORTEN para prognóstico.", category: "dermatologia", tags: ["ssj", "net", "nikolsky"] },
  { id: "fc-derm-03", front: "Quais as lesões elementares primárias em dermatologia?", back: "• Mácula/mancha: alteração de cor sem relevo\n• Pápula: elevação sólida < 1cm\n• Nódulo: elevação sólida > 1cm (profunda)\n• Placa: elevação achatada > 1cm\n• Vesícula: bolha < 1cm com líquido claro\n• Bolha: > 1cm com líquido claro\n• Pústula: coleção de pus\n• Urtica: placa edematosa transitória\n• Petéquia: ponto hemorrágico < 3mm", category: "dermatologia", tags: ["semiologia", "lesão elementar", "morfologia"] },
  { id: "fc-derm-04", front: "Regra ABCDE para avaliação de lesões melanocíticas?", back: "A — Assimetria\nB — Bordas irregulares\nC — Cor heterogênea (2+ cores)\nD — Diâmetro > 6mm\nE — Evolução (mudança recente)\n\nQualquer critério positivo → biópsia excisional. Dermoscopia auxilia. Breslow (espessura) é o principal fator prognóstico no melanoma.", category: "dermatologia", tags: ["melanoma", "abcde", "nevo"] },
  { id: "fc-derm-05", front: "Tratamento da psoríase — escalonamento?", back: "Leve (< 10% SC):\n• Corticoides tópicos + Calcipotriol\n• Coaltar, antralina\n\nModerada-grave (> 10% SC ou refratária):\n• Fototerapia (UVB narrow-band)\n• Metotrexato 15-25mg/sem\n• Ciclosporina\n\nGrave/refratária:\n• Imunobiológicos: anti-TNF (adalimumabe), anti-IL17 (secuquinumabe), anti-IL23 (guselcumabe)\n\nNUNCA usar corticoide sistêmico (rebote/pustulosa).", category: "dermatologia", tags: ["psoríase", "tratamento", "imunobiológico"] },
  { id: "fc-derm-06", front: "Diagnóstico diferencial de lesões bolhosas?", back: "• Pênfigo vulgar: bolhas flácidas, Nikolsky+, mucosa oral. Anti-desmogleína 1/3. Bx: acantólise suprabasal.\n• Penfigoide bolhoso: bolhas tensas, Nikolsky−, idosos. Anti-BP180/230. Bx: clivagem subepidérmica.\n• Dermatite herpetiforme: vesículas agrupadas, prurido intenso, doença celíaca. IgA granular na IFD.\n• Herpes zóster: vesículas em dermátomo, dor neuropática.", category: "dermatologia", tags: ["bolhosa", "pênfigo", "penfigoide"] },
  { id: "fc-derm-07", front: "Como classificar queimaduras por profundidade?", back: "1º grau: eritema, dor, sem bolhas (epiderme). Ex: queimadura solar.\n2º grau superficial: bolhas, fundo róseo, muito dolorosa (derme papilar).\n2º grau profunda: bolhas, fundo esbranquiçado, hipoestesia (derme reticular).\n3º grau: escara, indolor, não branqueia (toda derme).\n4º grau: músculo, osso, fáscia.\n\nFórmula de Parkland: 4ml × kg × %SCQ (Ringer Lactato).", category: "dermatologia", tags: ["queimadura", "parkland", "profundidade"] },
  { id: "fc-derm-08", front: "Farmacodermias mais comuns — drogas causadoras?", back: "• Exantema maculopapular (mais comum): ATB (amoxicilina, sulfonamidas)\n• Urticária/angioedema: AINEs, ATB, IECA (angioedema sem urticária)\n• SSJ/NET: Sulfonamidas, anticonvulsivantes (carbamazepina, fenitoína), alopurinol\n• DRESS: Anticonvulsivantes, dapsona, alopurinol (latência 2-8 sem, eosinofilia + hepatite)\n• Fotossensibilidade: Tetraciclinas, AINEs, amiodarona", category: "dermatologia", tags: ["farmacodermia", "reação adversa", "droga"] },
  { id: "fc-derm-09", front: "Tratamento da urticária aguda e crônica?", back: "Aguda (< 6 semanas):\n1. Anti-histamínico H1 2ª geração (cetirizina, loratadina)\n2. Se grave: corticoide curto (prednisona 3-5 dias)\n3. Se anafilaxia: adrenalina IM\n\nCrônica (> 6 semanas):\n1. Anti-H1 até 4x dose\n2. Associar anti-H1 1ª geração à noite\n3. Omalizumabe (anti-IgE) se refratária\n4. Ciclosporina (última linha)", category: "dermatologia", tags: ["urticária", "anti-histamínico", "omalizumabe"] },
  { id: "fc-derm-10", front: "Micoses superficiais — diagnóstico e tratamento?", back: "Dermatofitose (tinha): KOH + cultura. Tópico (terbinafina creme) se localizada. Sistêmico (terbinafina VO 250mg/dia ou itraconazol) se extensa ou ungueal.\n\nPitiríase versicolor (Malassezia): manchas hipo/hipercrômicas. KOH: 'espaguete com almôndegas'. Cetoconazol tópico.\n\nCandidíase: áreas intertriginosas, mucosas. Nistatina tópica ou fluconazol VO.", category: "dermatologia", tags: ["micose", "dermatofitose", "candidíase"] },
  { id: "fc-derm-11", front: "Diagnóstico e tratamento do herpes-zóster?", back: "Reativação de VZV no gânglio dorsal. Vesículas agrupadas em dermátomo, dor neuropática. Não cruza linha média.\n\nTratamento (< 72h do início):\n• Aciclovir 800mg 5x/dia por 7 dias OU\n• Valaciclovir 1g 3x/dia por 7 dias (melhor biodisponibilidade)\n\nComplicações: neuralgia pós-herpética (gabapentina/pregabalina), zóster oftálmico (urgência — encaminhar oftalmo), síndrome de Ramsay Hunt (paralisia facial + vesículas no ouvido).", category: "dermatologia", tags: ["herpes-zóster", "aciclovir", "neuralgia"] },
  { id: "fc-derm-12", front: "Hanseníase — classificação e tratamento poliquimioterapia?", back: "Paucibacilar (PB): ≤ 5 lesões, baciloscopia negativa. PQT 6 meses: rifampicina mensal + dapsona diária.\n\nMultibacilar (MB): > 5 lesões, baciloscopia pode ser positiva. PQT 12 meses: rifampicina + clofazimina mensais + dapsona + clofazimina diárias.\n\nReações:\nTipo 1 (reversa): prednisona.\nTipo 2 (ENH): talidomida (CI em gestantes!).", category: "dermatologia", tags: ["hanseníase", "pqt", "reação hansênica"] },
  { id: "fc-derm-13", front: "Acne vulgar — classificação e tratamento por gravidade?", back: "Grau I (comedoniana): retinoides tópicos (tretinoína, adapaleno).\nGrau II (papulopustulosa): + peróxido de benzoíla + ATB tópico (clindamicina).\nGrau III (nodulocística): + ATB oral (doxiciclina, minociclina) por até 3 meses.\nGrau IV (conglobata): isotretinoína oral 0.5-1mg/kg/dia.\nGrau V (fulminans): corticoide + isotretinoína.\n\nIsotretinoína: dose cumulativa 120-150mg/kg. CI: gestação (categoria X).", category: "dermatologia", tags: ["acne", "isotretinoína", "classificação"] },

  // ========== REUMATOLOGIA ==========
  { id: "fc-reuma-01", front: "Critérios classificatórios do Lúpus Eritematoso Sistêmico (ACR/EULAR 2019)?", back: "Critério de entrada: FAN ≥ 1:80.\nDomínios (pontuação):\n• Constitucional: febre\n• Hematológico: leucopenia, trombocitopenia, hemólise\n• Neuropsiquiátrico: convulsão, psicose, delirium\n• Mucocutâneo: alopecia, úlceras orais, rash malar, lúpus discoide\n• Serosas: derrame pleural/pericárdico\n• Musculoesquelético: artrite\n• Renal: proteinúria, nefrite classe III/IV\n• Imunológico: anti-dsDNA, anti-Sm, antifosfolípide, complemento baixo\n\nTotal ≥ 10 = classificação de LES.", category: "reumatologia", tags: ["lúpus", "les", "fan"] },
  { id: "fc-reuma-02", front: "Tratamento da Artrite Reumatoide — escalonamento?", back: "1. DMARD convencional: Metotrexato 15-25mg/sem (1ª escolha) + ácido fólico.\n2. Se intolerância: Leflunomida ou Sulfassalazina.\n3. Associação: MTX + Hidroxicloroquina + Sulfassalazina (terapia tripla).\n4. DMARD biológico: anti-TNF (adalimumabe, infliximabe), anti-IL6 (tocilizumabe), anti-CD20 (rituximabe).\n5. JAK-inibidores: tofacitinibe, baricitinibe.\n\nMeta: remissão ou baixa atividade em 6 meses (treat-to-target).", category: "reumatologia", tags: ["artrite reumatoide", "metotrexato", "biológico"] },
  { id: "fc-reuma-03", front: "Crise de gota aguda — tratamento e profilaxia?", back: "Crise aguda:\n1. AINEs em dose plena (indometacina, naproxeno) — 1ª escolha\n2. Colchicina 0.5mg 8/8h (melhor se < 12h do início)\n3. Corticoide (prednisona 30-40mg/dia ou infiltração articular)\n\nNUNCA iniciar ou alterar alopurinol durante crise.\n\nProfilaxia (iniciar após resolução):\n• Alopurinol 100mg → titular até uricemia < 6mg/dL\n• Colchicina 0.5mg/dia nos primeiros 6 meses\n• Febuxostate se intolerância ao alopurinol.", category: "reumatologia", tags: ["gota", "colchicina", "alopurinol"] },
  { id: "fc-reuma-04", front: "Critérios de vasculite — classificação por calibre do vaso?", back: "Grandes vasos:\n• Arterite de Takayasu (< 40 anos, aorta)\n• Arterite de células gigantes (> 50 anos, temporal)\n\nMédios vasos:\n• Poliarterite nodosa (PAN)\n• Kawasaki (crianças)\n\nPequenos vasos (ANCA):\n• Granulomatose com poliangiite (Wegener): c-ANCA/PR3\n• Poliangiite microscópica: p-ANCA/MPO\n• Granulomatose eosinofílica (Churg-Strauss): p-ANCA + eosinofilia + asma\n\nPequenos vasos (imunocomplexos):\n• Crioglobulinemia, IgA (Henoch-Schönlein)", category: "reumatologia", tags: ["vasculite", "anca", "calibre"] },
  { id: "fc-reuma-05", front: "Espondilite anquilosante — diagnóstico e tratamento?", back: "Critérios: lombalgia inflamatória (< 40 anos, início insidioso, melhora com exercício, piora com repouso, dor noturna) + sacroileíte na RM ou RX.\n\nHLA-B27 positivo em 90% (mas não é diagnóstico).\n\nTratamento:\n1. AINEs em dose plena (1ª linha — podem modificar progressão)\n2. Fisioterapia (fundamental)\n3. Anti-TNF se refratário (adalimumabe, etanercepte)\n4. Anti-IL17 (secuquinumabe) se falha anti-TNF\n\nNÃO usar MTX para doença axial.", category: "reumatologia", tags: ["espondilite", "hla-b27", "sacroileíte"] },
  { id: "fc-reuma-06", front: "Síndrome antifosfolípide — critérios e tratamento?", back: "Critérios de Sydney (≥1 clínico + ≥1 laboratorial):\nClínicos: trombose vascular (arterial/venosa) ou morbidade gestacional.\nLaboratoriais (confirmados em 12 semanas): anticoagulante lúpico, anticardiolipina IgG/IgM, anti-β2GP1 IgG/IgM.\n\nTratamento:\n• Trombose: anticoagulação com warfarina (INR 2-3) — indefinida\n• Gestação: heparina + AAS\n• SAF catastrófica: anticoagulação + corticoide + plasmaférese + IVIG", category: "reumatologia", tags: ["saf", "antifosfolípide", "trombose"] },
  { id: "fc-reuma-07", front: "Fibromialgia — diagnóstico e tratamento?", back: "Diagnóstico (critérios 2016): dor difusa ≥ 3 meses + WPI ≥ 7 e SSS ≥ 5 (OU WPI 4-6 e SSS ≥ 9). Sem exame que confirme.\n\nCaracterísticas: fadiga, sono não-reparador, disfunção cognitiva, sem inflamação articular.\n\nTratamento:\n1. Exercício aeróbico regular (maior nível de evidência)\n2. TCC (terapia cognitivo-comportamental)\n3. Duloxetina 60mg/dia ou Amitriptilina 25mg à noite\n4. Pregabalina 75-150mg 2x/dia\n5. Ciclobenzaprina 5-10mg à noite", category: "reumatologia", tags: ["fibromialgia", "dor crônica", "duloxetina"] },
  { id: "fc-reuma-08", front: "Esclerodermia — formas clínicas e autoanticorpos?", back: "Limitada (CREST): Calcinose, Raynaud, Esofagopatia, eSclerodactilia, Telangiectasia. Anti-centrômero. Melhor prognóstico.\n\nDifusa: acometimento cutâneo extenso, fibrose pulmonar, crise renal esclerodérmica. Anti-topoisomerase I (anti-Scl-70). Pior prognóstico.\n\nCrise renal: IECA (captopril) — NUNCA suspender mesmo com IRA.\n\nFibrose pulmonar: nintedanibe ou micofenolato.", category: "reumatologia", tags: ["esclerodermia", "crest", "anti-scl70"] },
  { id: "fc-reuma-09", front: "Miopatias inflamatórias — dermatomiosite vs polimiosite?", back: "Polimiosite: fraqueza proximal simétrica, CPK elevada, anti-Jo1 (sd antissintetase).\n\nDermatomiosite: + manifestações cutâneas: heliótropo (pálpebras), pápulas de Gottron (MCF/IFP), sinal do xale. Anti-Mi2.\nAssociação com neoplasia (rastreio obrigatório!).\n\nTratamento:\n1. Corticoide (prednisona 1mg/kg/dia)\n2. Metotrexato ou Azatioprina (poupadores)\n3. IVIG se refratário\n4. Rituximabe em casos graves", category: "reumatologia", tags: ["dermatomiosite", "polimiosite", "gottron"] },
  { id: "fc-reuma-10", front: "Artrite séptica — diagnóstico e tratamento?", back: "Suspeitar: monoartrite aguda + febre + sinais flogísticos intensos.\n\nDiagnóstico: artrocentese → líquido sinovial purulento, leucócitos > 50.000 (PMN > 75%), Gram e cultura.\n\nTratamento empírico:\n• Adultos: Oxacilina 2g IV 4/4h (cobrir S. aureus)\n• Se risco MRSA: Vancomicina\n• Se risco Gram−: + Ceftriaxone\n• Gonocócica: Ceftriaxone 1g IV/dia\n\nDrenagem articular é OBRIGATÓRIA (punção seriada ou artroscopia).", category: "reumatologia", tags: ["artrite séptica", "artrocentese", "monoartrite"] },
  { id: "fc-reuma-11", front: "Polimialgia reumática — diagnóstico e tratamento?", back: "Critérios: > 50 anos, dor e rigidez em cinturas (escapular E pélvica), rigidez matinal > 45min, VHS/PCR elevados.\n\nCPK NORMAL (diferencia de miopatias).\nAssociação com arterite de células gigantes (15-20%).\n\nTratamento: Prednisona 15-20mg/dia (resposta DRAMÁTICA em 24-72h). Redução gradual ao longo de 12-24 meses.\n\nSe refratário: MTX como poupador de corticoide.", category: "reumatologia", tags: ["polimialgia", "arterite temporal", "corticoide"] },
  { id: "fc-reuma-12", front: "Artrite psoriásica — padrões e tratamento?", back: "5 padrões:\n1. Oligoarticular assimétrica (mais comum)\n2. Poliarticular simétrica (símile AR)\n3. Distal (IFD — característico)\n4. Mutilante (rara, grave)\n5. Espondilítica\n\nCaracterísticas: dactilite ('dedo em salsicha'), entesite, psoríase cutânea/ungueal.\n\nTratamento: AINEs → MTX → anti-TNF ou anti-IL17 → anti-IL23. Apremilast (inibidor PDE4) como opção.", category: "reumatologia", tags: ["artrite psoriásica", "dactilite", "il17"] },

  // ========== ORTOPEDIA ==========
  { id: "fc-orto-01", front: "Classificação de Gustilo-Anderson para fraturas expostas?", back: "Tipo I: ferida < 1cm, mínima contaminação, traço simples.\nTipo II: ferida 1-10cm, contaminação moderada, sem lesão extensa de partes moles.\nTipo IIIA: ferida > 10cm, alta energia, cobertura de partes moles adequada.\nTipo IIIB: perda de partes moles com exposição óssea, necessita retalho.\nTipo IIIC: lesão vascular associada que necessita reparo.\n\nATB: I-II: Cefalosporina 1ª. III: + aminoglicosídeo. Contaminada: + penicilina.", category: "ortopedia", tags: ["fratura exposta", "gustilo", "classificação"] },
  { id: "fc-orto-02", front: "Síndrome compartimental — diagnóstico e tratamento?", back: "Diagnóstico CLÍNICO (6 P's): Pain (dor desproporcional), Pressure (tensão), Pain on passive stretch (DOR À EXTENSÃO PASSIVA — mais precoce), Paresthesia, Pallor, Pulselessness (tardio!).\n\nPressão compartimental > 30mmHg ou delta P < 30mmHg (diastólica − compartimental).\n\nTratamento: FASCIOTOMIA DE URGÊNCIA.\nAtrasos > 6h = rabdomiólise, IRA, amputação.\nNÃO elevar o membro. NÃO aplicar gelo. REMOVER gesso/talas.", category: "ortopedia", tags: ["síndrome compartimental", "fasciotomia", "6ps"] },
  { id: "fc-orto-03", front: "Manejo inicial de fratura de fêmur proximal em idosos?", back: "Classificação de Garden (intracapsular):\nI-II (sem desvio): fixação com parafusos canulados.\nIII-IV (com desvio): artroplastia (parcial se baixa demanda, total se ativo).\n\nExtracapsulares (transtrocantéricas): fixação com haste intramedular (DHS ou PFN).\n\nPrazo cirúrgico ideal: < 48h (↓mortalidade).\nAnticoagulação profilática. Mobilização precoce.", category: "ortopedia", tags: ["fratura fêmur", "garden", "artroplastia"] },
  { id: "fc-orto-04", front: "Luxação de ombro — diagnóstico e redução?", back: "Anterior (95%): mecanismo de abdução + rotação externa. Deformidade em dragona, sinal da tecla. RX: AP + axilar lateral.\n\nTécnicas de redução:\n• Kocher (rotação externa → adução → rotação interna)\n• Estimulação de Cunningham (massagem dos músculos)\n• Tração-contratração\n• Milch\n\nPós-redução: tipoia 2-3 semanas, RX controle.\nLesões associadas: Hill-Sachs, Bankart, lesão do nervo axilar (deltóide).", category: "ortopedia", tags: ["luxação ombro", "kocher", "bankart"] },
  { id: "fc-orto-05", front: "Classificação de Ottawa para indicação de RX de tornozelo?", back: "Solicitar RX se:\n• Dor na zona maleolar + qualquer um:\n  - Dor à palpação dos 6cm distais da fíbula posterior ou tíbia posterior\n  - Incapacidade de dar 4 passos\n\n• Dor no mediopé + qualquer um:\n  - Dor à palpação do navicular ou base do 5º metatarso\n  - Incapacidade de dar 4 passos\n\nSensibilidade ~100% para fraturas significativas. Reduz RX desnecessários em ~40%.", category: "ortopedia", tags: ["ottawa", "tornozelo", "fratura"] },
  { id: "fc-orto-06", front: "Fraturas mais comuns em crianças — particularidades?", back: "• Fratura em torus (buckle): compressão cortical, estável. Imobilização simples.\n• Fratura em galho verde: cortical rompida de um lado. Pode necessitar redução.\n• Fratura da placa de crescimento (Salter-Harris):\n  I: através da fise\n  II: fise + metáfise (mais comum)\n  III: fise + epífise\n  IV: metáfise + fise + epífise\n  V: compressão/esmagamento da fise\n\nRisco de distúrbio de crescimento: tipos III-V.", category: "ortopedia", tags: ["fratura pediátrica", "salter-harris", "placa crescimento"] },
  { id: "fc-orto-07", front: "Fratura de Colles vs Smith — diferenças?", back: "Colles: fratura do rádio distal com desvio DORSAL ('deformidade em garfo'). Mecanismo: queda com mão em extensão (FOOSH). Mais comum.\n\nSmith: fratura do rádio distal com desvio VOLAR ('Colles reversa'). Mecanismo: queda com mão em flexão.\n\nTratamento:\n• Sem desvio: gesso axilopalmar 6 semanas\n• Com desvio: redução fechada + gesso\n• Instável/articular: fixação cirúrgica (placa volar)", category: "ortopedia", tags: ["colles", "smith", "rádio distal"] },
  { id: "fc-orto-08", front: "Lombalgia — bandeiras vermelhas?", back: "• Idade < 20 ou > 55 anos (início recente)\n• Trauma significativo\n• Dor noturna ou em repouso (progressiva)\n• Perda de peso inexplicada\n• História de neoplasia\n• Febre\n• Uso de corticoides/imunossupressão\n• Déficit neurológico progressivo\n• Síndrome da cauda equina: retenção urinária, anestesia em sela, fraqueza bilateral\n\nSíndrome da cauda equina = EMERGÊNCIA CIRÚRGICA (descompressão < 48h).", category: "ortopedia", tags: ["lombalgia", "bandeira vermelha", "cauda equina"] },
  { id: "fc-orto-09", front: "Teste de Phalen e Tinel — o que avaliam?", back: "Ambos avaliam SÍNDROME DO TÚNEL DO CARPO (compressão do nervo mediano).\n\nPhalen: flexão forçada dos punhos por 60s → positivo se parestesia no território do mediano (polegar, indicador, médio, metade radial do anular).\n\nTinel: percussão sobre o túnel do carpo → parestesia/choque.\n\nDiagnóstico: ENMG (padrão-ouro).\nTratamento: tala noturna + AINEs → infiltração com corticoide → descompressão cirúrgica.", category: "ortopedia", tags: ["túnel carpo", "phalen", "tinel"] },
  { id: "fc-orto-10", front: "Osteomielite — diagnóstico e tratamento?", back: "Aguda hematogênica (crianças): S. aureus. Febre + dor óssea + recusa de deambulação.\nCrônica/contiguidade (adultos): pós-trauma/cirurgia, úlcera de pressão.\n\nDiagnóstico: PCR/VHS elevados, hemocultura, RM (padrão-ouro de imagem), biópsia óssea (padrão-ouro microbiológico).\n\nTratamento:\n• ATB IV 4-6 semanas: Oxacilina ou Vancomicina (MRSA)\n• Desbridamento cirúrgico se sequestro ósseo\n• Crônica: pode necessitar 3-6 meses de ATB", category: "ortopedia", tags: ["osteomielite", "rm", "desbridamento"] },
  { id: "fc-orto-11", front: "Entorse de tornozelo — classificação e tratamento?", back: "Grau I: estiramento ligamentar, sem instabilidade. Edema leve.\nGrau II: ruptura parcial, instabilidade moderada. Edema/equimose.\nGrau III: ruptura completa, instabilidade franca. Edema importante.\n\nLigamento mais acometido: talofibular anterior (inversão).\n\nTratamento (PRICE):\nP: proteção\nR: repouso relativo\nI: ice (gelo 20min 4-6x/dia)\nC: compressão elástica\nE: elevação\n\nGrau III: imobilização funcional 3-6 semanas. Cirurgia raro.", category: "ortopedia", tags: ["entorse", "tornozelo", "price"] },
  { id: "fc-orto-12", front: "Fratura de escafoide — por que é especial?", back: "• Fratura mais comum do carpo (queda FOOSH)\n• RX inicial pode ser NORMAL em 15-20% (falso negativo)\n• Se suspeita clínica (dor na tabaqueira anatômica) + RX normal → imobilizar e repetir RX em 10-14 dias ou solicitar RM\n• Vascularização retrógrada → risco de necrose avascular (polo proximal)\n• Pseudoartrose é complicação frequente se não tratada\n\nTratamento: gesso incluindo polegar 8-12 semanas. Cirúrgica se desviada.", category: "ortopedia", tags: ["escafoide", "tabaqueira", "necrose avascular"] },

  // ========== MEDICINA DE FAMÍLIA ==========
  { id: "fc-mf-01", front: "Rastreamento de câncer — recomendações brasileiras atualizadas?", back: "Mama: mamografia bienal 50-69 anos (INCA). Exame clínico anual > 40 anos.\nColo uterino: citologia (Papanicolaou) 25-64 anos, a cada 3 anos após 2 normais anuais.\nColorretal: pesquisa de sangue oculto anual ou colonoscopia a cada 10 anos, 50-75 anos.\nPróstata: NÃO rastrear de rotina (INCA). Decisão compartilhada 50-75 anos.\n\nPulmão: TC de baixa dose anual em tabagistas > 50 anos com carga ≥ 20 maços/ano.", category: "medicina_familia", tags: ["rastreamento", "câncer", "prevenção"] },
  { id: "fc-mf-02", front: "Calendário vacinal do adulto — vacinas essenciais?", back: "• dT (difteria/tétano): reforço a cada 10 anos\n• Hepatite B: 3 doses se esquema incompleto\n• Tríplice viral: 2 doses até 29 anos, 1 dose 30-59 anos\n• Febre amarela: dose única (áreas endêmicas)\n• Influenza: anual (≥ 60 anos, gestantes, comorbidades)\n• Pneumocócica 23v: ≥ 60 anos, institucionalizados\n• COVID-19: esquema vigente\n\nGestantes: dTpa (27-36 semanas), Influenza, Hepatite B.", category: "medicina_familia", tags: ["vacina", "adulto", "calendário"] },
  { id: "fc-mf-03", front: "SCORE de risco cardiovascular — estratificação e metas?", back: "Muito alto risco: doença aterosclerótica prévia, DM com LOA → LDL < 50mg/dL\nAlto risco: LDL ≥ 190 (hipercolesterolemia familiar), DM sem LOA → LDL < 70mg/dL\nRisco intermediário: homens ≥ 50 ou mulheres ≥ 60 + 1 fator → LDL < 100mg/dL\nBaixo risco: sem fatores → LDL < 130mg/dL\n\nEstatinas: sinvastatina, atorvastatina, rosuvastatina.\nMudança de estilo de vida: SEMPRE, independente do risco.", category: "medicina_familia", tags: ["risco cardiovascular", "ldl", "estatina"] },
  { id: "fc-mf-04", front: "Abordagem centrada na pessoa (método clínico centrado na pessoa)?", back: "6 componentes (Stewart et al.):\n1. Explorar a doença E a experiência da doença (sentimentos, ideias, funcionalidade, expectativas — FIFE)\n2. Entender a pessoa como um todo (contexto, família, trabalho)\n3. Elaborar plano conjunto de manejo\n4. Incorporar prevenção e promoção\n5. Intensificar a relação médico-paciente\n6. Ser realista (recursos, tempo, equipe)\n\nFerramenta P.R.A.C.T.I.C.E. para plano de cuidado.", category: "medicina_familia", tags: ["mccp", "pessoa", "consulta"] },
  { id: "fc-mf-05", front: "Princípios da Atenção Primária à Saúde (Starfield)?", back: "4 atributos essenciais:\n1. Acesso/Primeiro contato: porta de entrada do sistema\n2. Longitudinalidade: vínculo ao longo do tempo\n3. Integralidade: cuidado abrangente (promoção, prevenção, cura, reabilitação)\n4. Coordenação do cuidado: organização dos fluxos na RAS\n\n3 atributos derivados:\n5. Orientação familiar\n6. Orientação comunitária\n7. Competência cultural", category: "medicina_familia", tags: ["aps", "starfield", "atributos"] },
  { id: "fc-mf-06", front: "Genograma familiar — símbolos básicos e utilidade?", back: "Símbolos:\n• Quadrado: homem. Círculo: mulher.\n• Linha horizontal: casamento. Barras: separação (1), divórcio (2).\n• Linha vertical: filhos. X sobre símbolo: falecimento.\n• Linha dupla: relação forte. Linha zigue-zague: conflito.\n\nUtilidade: identificar padrões de doença familiar, dinâmica relacional, rede de apoio, ciclo de vida familiar. Mínimo 3 gerações.\n\nFerramentas complementares: ecomapa (rede social), APGAR familiar (funcionalidade).", category: "medicina_familia", tags: ["genograma", "família", "ferramenta"] },
  { id: "fc-mf-07", front: "Abordagem do tabagismo na APS — protocolo?", back: "Avaliação: Fagerström (dependência) + estágio de mudança (Prochaska-DiClemente).\n\n5 A's:\nAsk (perguntar), Advise (aconselhar), Assess (avaliar prontidão), Assist (ajudar), Arrange (agendar seguimento).\n\nTratamento:\n1. TCC (terapia cognitivo-comportamental) em grupo — 4 sessões semanais + manutenção\n2. Farmacoterapia:\n   • Adesivo de nicotina 21mg → 14mg → 7mg (12 semanas)\n   • Bupropiona 150mg 2x/dia\n   • Vareniclina 1mg 2x/dia (mais eficaz)", category: "medicina_familia", tags: ["tabagismo", "cessação", "fagerström"] },
  { id: "fc-mf-08", front: "Teste do pezinho — doenças rastreadas?", back: "Teste básico (SUS - 6 doenças):\n1. Fenilcetonúria (PKU)\n2. Hipotireoidismo congênito\n3. Doença falciforme e hemoglobinopatias\n4. Fibrose cística\n5. Hiperplasia adrenal congênita\n6. Deficiência de biotinidase\n\nTeste ampliado (2022): + toxoplasmose congênita, galactosemia, aminoacidopatias, distúrbios do ciclo da ureia, acidemias orgânicas e outras.\n\nColeta ideal: 3º ao 5º dia de vida.", category: "medicina_familia", tags: ["pezinho", "triagem neonatal", "rastreamento"] },
  { id: "fc-mf-09", front: "APGAR familiar — o que avalia?", back: "Avalia funcionalidade familiar em 5 domínios:\nA — Adaptação (resolução de problemas)\nP — Participação (compartilhamento de decisões)\nG — Growth/Crescimento (liberdade para amadurecer)\nA — Afeto (expressão de emoções)\nR — Resolução (compartilhamento de tempo/recursos)\n\nPontuação 0-2 cada (total 0-10):\n• 7-10: boa funcionalidade\n• 4-6: moderada disfunção\n• 0-3: elevada disfunção\n\nAplicar periodicamente, especialmente em famílias vulneráveis.", category: "medicina_familia", tags: ["apgar familiar", "funcionalidade", "ferramenta"] },
  { id: "fc-mf-10", front: "Pré-natal de baixo risco — rotina de exames?", back: "1º trimestre: hemograma, tipagem/Rh/Coombs, glicemia, EAS+urocultura, HIV, VDRL, HBsAg, toxoplasmose IgG/IgM, USG obstétrica (11-14sem).\n\n2º trimestre: TOTG 75g (24-28sem), hemograma, EAS+urocultura.\n\n3º trimestre: hemograma, HIV, VDRL, HBsAg, EAS+urocultura, Streptococcus grupo B (35-37sem).\n\nMínimo 6 consultas (ideal ≥ 8). Ácido fólico 5mg até 12ª semana. Sulfato ferroso a partir do 2º trimestre.", category: "medicina_familia", tags: ["pré-natal", "exames", "gestação"] },
  { id: "fc-mf-11", front: "Classificação de risco familiar — escala de Coelho-Savassi?", back: "Sentinelas de risco (pontuação):\n• Acamado (3)\n• Deficiência física/mental (3)\n• Baixas condições de saneamento (3)\n• Desnutrição grave (3)\n• Drogadição/alcoolismo (2)\n• Desemprego (2)\n• Analfabetismo (1)\n• Menor de 6 meses (1)\n• Maior de 70 anos (1)\n• HAS (1)\n• DM (1)\n• Relação morador/cômodo > 1 (3)\n\nR0: 0-4 (sem risco) → R3: ≥ 11 (risco máximo)", category: "medicina_familia", tags: ["risco familiar", "coelho-savassi", "estratificação"] },
  { id: "fc-mf-12", front: "Territorialização e diagnóstico comunitário na ESF?", back: "Territorialização: processo de reconhecimento e mapeamento do território adscrito.\n\nIdentificar:\n• Demografia e pirâmide etária\n• Condições socioeconômicas\n• Equipamentos sociais (escolas, igrejas, associações)\n• Riscos ambientais\n• Perfil epidemiológico (doenças prevalentes)\n• Barreiras de acesso\n\nFerramentas: mapa inteligente, cadastro familiar (e-SUS), estimativa rápida, SIAB.\n\nBase para: planejamento de ações, priorização de visitas, programação de oferta.", category: "medicina_familia", tags: ["territorialização", "esf", "diagnóstico comunitário"] },
  { id: "fc-mf-13", front: "Visita domiciliar — indicações e critérios de priorização?", back: "Indicações:\n• Acamados e restritos ao domicílio\n• Puérperas e RN (1ª semana de vida)\n• Pós-alta hospitalar\n• Idosos frágeis\n• Pacientes em cuidados paliativos\n• Busca ativa de faltosos\n• Investigação de contatos (TB, hanseníase)\n\nPriorizar: Coelho-Savassi R2-R3, famílias com sentinelas de risco.\n\nEquipe mínima: médico + enfermeiro + ACS. ACS: visita mensal a todas as famílias.", category: "medicina_familia", tags: ["visita domiciliar", "acs", "esf"] },

  // ========== OFTALMOLOGIA ==========
  { id: "fc-oftalmo-01", front: "Glaucoma agudo de ângulo fechado — diagnóstico e tratamento?", back: "Clínica: dor ocular intensa, olho vermelho, visão turva, halos coloridos, cefaleia, náuseas/vômitos, pupila médio-fixa, edema de córnea, PIO > 40mmHg.\n\nTratamento imediato:\n1. Timolol 0.5% colírio 1 gota\n2. Pilocarpina 2% 1 gota a cada 15min (3x)\n3. Acetazolamida 500mg IV ou VO\n4. Manitol 20% 1-2g/kg IV se PIO > 50\n5. Iridotomia a laser (definitivo)\n\nÉ EMERGÊNCIA oftalmológica!", category: "oftalmologia", tags: ["glaucoma", "ângulo fechado", "emergência"] },
  { id: "fc-oftalmo-02", front: "Diagnóstico diferencial do olho vermelho agudo?", back: "Conjuntivite: hiperemia difusa, secreção, sem dor importante, acuidade visual preservada.\nUveíte anterior: dor, fotofobia, miose, injeção ciliar (perilímbica), células na câmara anterior.\nGlaucoma agudo: dor intensa, pupila fixa semidilatada, PIO elevada, edema corneal.\nCeratite: dor, fotofobia, defeito epitelial (fluoresceína+), lacrimejamento.\nEsclerite: dor intensa à palpação, hiperemia violácea, associada a doenças autoimunes.\n\nREGRA: dor + fotofobia + baixa acuidade = ENCAMINHAR URGENTE.", category: "oftalmologia", tags: ["olho vermelho", "diagnóstico diferencial", "urgência"] },
  { id: "fc-oftalmo-03", front: "Descolamento de retina — sinais e conduta?", back: "Sintomas: flashes luminosos (fotopsia), floaters ('moscas volantes') súbitos, cortina/sombra no campo visual.\n\nFatores de risco: miopia alta, cirurgia de catarata prévia, trauma, história familiar.\n\nConduta: ENCAMINHAMENTO OFTALMOLÓGICO DE URGÊNCIA (< 24h).\nO paciente deve permanecer em repouso.\nTipo regmatogênico (mais comum): cirurgia (vitrectomia, crioterapia, fotocoagulação, introflexão escleral).\n\nNÃO dilatar pupila no PS sem avaliação oftalmológica.", category: "oftalmologia", tags: ["descolamento retina", "fotopsia", "urgência"] },
  { id: "fc-oftalmo-04", front: "Queimadura química ocular — conduta imediata?", back: "IRRIGAÇÃO COPIOSA IMEDIATA — ANTES de qualquer avaliação!\n\nProtocolo:\n1. Irrigar com SF 0.9% ou água limpa por pelo menos 30 minutos\n2. Verificar pH (objetivo: pH 7.0-7.4)\n3. Se pH não normalizar: continuar irrigação\n4. Eversão palpebral para remover partículas\n5. Anestésico tópico para facilitar irrigação\n6. Encaminhar oftalmologia URGENTE\n\nÁlcali (cal, amônia, soda) = PIOR prognóstico (penetração profunda).\nÁcido: coagulação proteica limita penetração.", category: "oftalmologia", tags: ["queimadura química", "irrigação", "emergência"] },
  { id: "fc-oftalmo-05", front: "Retinopatia diabética — classificação e tratamento?", back: "Não-proliferativa:\n• Leve: microaneurismas isolados\n• Moderada: hemorragias, exsudatos duros\n• Grave (regra 4-2-1): hemorragias em 4 quadrantes OU veias em rosário em 2 quadrantes OU IRMA em 1 quadrante\n\nProliferativa: neovasos (disco/retina). Risco de hemorragia vítrea e descolamento tracional.\n\nTratamento:\n• Anti-VEGF intravítreo (ranibizumabe, aflibercepte)\n• Fotocoagulação panretiniana (proliferativa)\n• Controle rigoroso de glicemia (HbA1c < 7%) e PA\n\nRastreio: anual a partir do diagnóstico de DM2.", category: "oftalmologia", tags: ["retinopatia diabética", "anti-vegf", "fotocoagulação"] },
  { id: "fc-oftalmo-06", front: "Celulite orbitária vs pré-septal — diferenças?", back: "Pré-septal (periorbitária): edema/eritema palpebral, SEM proptose, SEM dor à movimentação, acuidade visual normal. Causa: sinusite, trauma, picada.\n\nOrbitária: proptose, dor à movimentação, restrição de motilidade, quemose, pode ter baixa acuidade visual. Pode complicar com trombose de seio cavernoso, abscesso subperiosteal.\n\nConduta:\n• Pré-septal leve: ATB oral (amoxicilina-clavulanato)\n• Orbitária: INTERNAÇÃO + ATB IV (ceftriaxone + oxacilina) + TC de órbitas\n• Cirurgia se abscesso > 1cm ou sem melhora em 48h", category: "oftalmologia", tags: ["celulite orbitária", "pré-septal", "proptose"] },
  { id: "fc-oftalmo-07", front: "Oclusão de artéria central da retina — diagnóstico e conduta?", back: "Clínica: perda visual SÚBITA, INDOLOR, unilateral. Cherry-red spot na fundoscopia. DPAR (defeito pupilar aferente relativo).\n\nJanela terapêutica: < 4-6 horas (análogo ao AVC).\n\nConduta imediata:\n1. Massagem ocular (compressão intermitente)\n2. Reduzir PIO: timolol + acetazolamida\n3. Carbogênio (O₂ 95% + CO₂ 5%) — vasodilatação\n4. Paracentese de câmara anterior (especialista)\n5. Investigar fonte embólica (carótida, cardíaca)\n\nPrognóstico visual geralmente ruim.", category: "oftalmologia", tags: ["oclusão arterial", "cherry-red spot", "emergência"] },
  { id: "fc-oftalmo-08", front: "Teste de Ishihara e avaliação de acuidade visual?", back: "Ishihara: rastreio de discromatopsia (daltonismo). Placas pseudoisocromáticas. Avalia eixo vermelho-verde. Teste monocular.\n\nAcuidade visual:\n• Tabela de Snellen: distância 6m (20 pés). Normal: 20/20.\n• Perto: tabela de Jaeger.\n• Crianças < 3 anos: fixação e seguimento.\n• Teste do olhinho (reflexo vermelho): rastreio neonatal — catarata congênita, retinoblastoma, glaucoma congênito.\n\nEncaminhar se AV < 20/40 ou assimetria ≥ 2 linhas entre os olhos.", category: "oftalmologia", tags: ["acuidade visual", "snellen", "ishihara"] },
  { id: "fc-oftalmo-09", front: "Conjuntivite neonatal — causas por tempo de início?", back: "Primeiras 24h: química (nitrato de prata — profilaxia de Credé).\n2-5 dias: gonocócica (N. gonorrhoeae) — secreção purulenta intensa, URGÊNCIA (risco de perfuração corneal). Tto: Ceftriaxone 25-50mg/kg IM dose única.\n5-14 dias: clamídia (C. trachomatis) — secreção mucopurulenta. Tto: Eritromicina xarope 50mg/kg/dia VO por 14 dias (risco de pneumonia).\n> 14 dias: herpes simples — vesículas palpebrais. Tto: Aciclovir IV.\n\nProfilaxia atual: eritromicina pomada oftálmica ao nascer.", category: "oftalmologia", tags: ["conjuntivite neonatal", "credé", "gonocócica"] },
  { id: "fc-oftalmo-10", front: "Papiledema — causas e diagnóstico?", back: "Papiledema = edema de papila BILATERAL por hipertensão intracraniana.\n\nCausas: tumores cerebrais, hidrocefalia, pseudotumor cerebri (HIC idiopática), trombose venosa cerebral, meningite.\n\nFundoscopia: borramento das margens do disco, elevação do disco, perda de pulsação venosa espontânea, hemorragias peripapilares.\n\nConduta: TC/RM de crânio ANTES de punção lombar. Se normal → PL com manometria.\n\nPseudotumor cerebri: mulheres obesas em idade fértil. Tto: acetazolamida + perda de peso.", category: "oftalmologia", tags: ["papiledema", "hic", "fundoscopia"] },
  { id: "fc-oftalmo-11", front: "Trauma ocular perfurante — conduta?", back: "Sinais: laceração corneana/escleral, câmara anterior rasa, hipotonia, hifema, pupila irregular (corectopia), herniação de íris/vítreo.\n\nConduta:\n1. NÃO manipular o globo, NÃO remover corpo estranho\n2. Protetor ocular rígido (escudo de Fox) — sem compressão\n3. Antieméticos (evitar Valsalva)\n4. ATB sistêmico profilático\n5. Atualizar vacina antitetânica\n6. TC de órbita (NÃO RM se suspeita de metal)\n7. Encaminhar cirurgia oftalmológica URGENTE\n\nJEJUM (preparo para cirurgia).", category: "oftalmologia", tags: ["trauma ocular", "perfurante", "corpo estranho"] },
  { id: "fc-oftalmo-12", front: "Estrabismo na criança — quando investigar?", back: "Pseudoestrabismo: epicanto largo simula esotropia — teste de Hirschberg normal (reflexo corneal simétrico).\n\nEstrabismo verdadeiro: reflexo corneal assimétrico, cover test positivo.\n\nReferência URGENTE:\n• Qualquer estrabismo > 6 meses de idade\n• Estrabismo intermitente > 4 meses\n• Esotropia constante em qualquer idade\n• Leucocoria (excluir retinoblastoma!)\n\nTratamento: correção óptica, oclusão (ambliopia), cirurgia se necessário.\nAmbliopia: tratar antes dos 7 anos (período crítico).", category: "oftalmologia", tags: ["estrabismo", "ambliopia", "hirschberg"] },

  // ========== OTORRINOLARINGOLOGIA ==========
  { id: "fc-orl-01", front: "Otite média aguda — diagnóstico e tratamento?", back: "Diagnóstico: otalgia + abaulamento de MT + efusão em ouvido médio.\nOtoscopia: MT hiperemiada, abaulada, opaca, com perda de mobilidade.\n\nTratamento:\n• < 6 meses: ATB sempre\n• 6 meses-2 anos: ATB se bilateral ou grave; observar 48-72h se unilateral leve\n• > 2 anos: observar 48-72h se leve; ATB se grave\n\n1ª escolha: Amoxicilina 50mg/kg/dia (90mg/kg/dia se risco de resistência).\nFalha: Amoxicilina-clavulanato. Alérgicos: Ceftriaxone IM.", category: "otorrino", tags: ["otite média", "amoxicilina", "criança"] },
  { id: "fc-orl-02", front: "Corpo estranho em ouvido e nariz — manejo?", back: "Ouvido:\n• Insetos vivos: imobilizar com lidocaína ou óleo mineral, depois remover\n• Objetos: irrigação (se MT íntegra), curetas, pinça\n• NÃO irrigar se: pilha/bateria, material higroscópico, perfuração de MT\n\nNariz:\n• Técnica do 'beijo da mãe': ocluir narina contralateral, soprar na boca\n• Pinça jacaré ou aspiração\n• PILHA/BATERIA = EMERGÊNCIA (necrose em 2-4h → perfuração septal)\n\nSedação/anestesia geral se criança não cooperativa após 1-2 tentativas.", category: "otorrino", tags: ["corpo estranho", "ouvido", "nariz"] },
  { id: "fc-orl-03", front: "Epistaxe — classificação e tratamento?", back: "Anterior (90%): plexo de Kiesselbach (Little). Tratamento:\n1. Compressão digital 10-15min\n2. Cauterização com nitrato de prata\n3. Tampão anterior (merocel, gelfoam)\n\nPosterior (10%): artéria esfenopalatina. Mais grave.\n1. Tampão posterior (sonda de Foley ou cateter balão)\n2. Embolização angiográfica\n3. Ligadura arterial cirúrgica\n\nInvestigar: HAS, coagulopatia, uso de anticoagulantes, tumores (angiofibroma juvenil em adolescentes).", category: "otorrino", tags: ["epistaxe", "tampão", "kiesselbach"] },
  { id: "fc-orl-04", front: "VPPB — diagnóstico e tratamento?", back: "Vertigem Posicional Paroxística Benigna: vertigem breve (< 1min) desencadeada por mudança de posição da cabeça.\n\nDiagnóstico: manobra de Dix-Hallpike → nistagmo rotatório/vertical com latência, fatigável, duração < 30s. Canal posterior (mais comum).\n\nTratamento: manobra de reposicionamento de Epley (95% eficácia). NÃO usar supressores vestibulares cronicamente.\n\nDiagnóstico diferencial: neurite vestibular (vertigem contínua), Ménière (vertigem + hipoacusia + plenitude + zumbido), AVC cerebelar (sem latência, sem fadiga).", category: "otorrino", tags: ["vppb", "dix-hallpike", "epley"] },
  { id: "fc-orl-05", front: "Abscesso periamigdaliano — diagnóstico e tratamento?", back: "Clínica: odinofagia UNILATERAL intensa, trismo, voz abafada ('batata quente'), desvio da úvula, abaulamento periamigdaliano.\n\nDiagnóstico: clínico. TC se dúvida ou complicação.\n\nTratamento:\n1. Drenagem (punção aspirativa ou incisão) — fundamental\n2. ATB IV: Amoxicilina-clavulanato ou Clindamicina\n3. Corticoide: Dexametasona (reduz edema e dor)\n4. Hidratação + analgesia\n\nComplicações: extensão para espaço parafaríngeo, mediastinite, obstrução de vias aéreas.\nAmigdalectomia: considerar se recorrente.", category: "otorrino", tags: ["abscesso periamigdaliano", "drenagem", "trismo"] },
  { id: "fc-orl-06", front: "Surdez súbita — conduta de emergência?", back: "Definição: perda auditiva neurossensorial ≥ 30dB em 3 frequências consecutivas em < 72h.\n\nCausas: idiopática (maioria), viral, vascular, autoimune, schwannoma vestibular.\n\nConduta:\n1. Audiometria URGENTE\n2. RM com gadolíneo (excluir schwannoma)\n3. Corticoterapia precoce: Prednisona 1mg/kg/dia por 14 dias com desmame\n4. Corticoide intratimpânico (resgate ou adjuvante)\n5. Iniciar em < 2 semanas (melhor prognóstico < 72h)\n\nRecuperação: 1/3 total, 1/3 parcial, 1/3 sem melhora.", category: "otorrino", tags: ["surdez súbita", "emergência", "corticoide"] },
  { id: "fc-orl-07", front: "Epiglotite aguda — diagnóstico e manejo?", back: "Criança: H. influenzae tipo b (raro pós-vacina). Adulto: S. pyogenes, S. pneumoniae, S. aureus.\n\nClínica: início súbito, odinofagia intensa, sialorreia, voz abafada, estridor, posição de tripé, toxemia.\n\nConduta:\n1. NÃO examinar orofaringe (risco de obstrução total)\n2. Manter calmo, posição confortável\n3. Via aérea: IOT precoce em centro cirúrgico (anestesista + ORL)\n4. ATB IV: Ceftriaxone + corticoide (dexametasona)\n5. RX lateral cervical: 'sinal do polegar' (epiglote edemaciada)\n\nCricotireoidostomia se impossibilidade de IOT.", category: "otorrino", tags: ["epiglotite", "via aérea", "sinal polegar"] },
  { id: "fc-orl-08", front: "Sinusite aguda vs crônica — diagnóstico e tratamento?", back: "Aguda bacteriana (> 10 dias ou piora após 5-7 dias):\n• Dor facial, congestão, rinorreia purulenta, hiposmia\n• 1ª linha: Amoxicilina 7-10 dias. Falha: Amoxicilina-clavulanato\n• Descongestionante tópico (máximo 5 dias) + lavagem nasal\n\nCrônica (> 12 semanas):\n• Com pólipos: corticoide nasal + lavagem. Cirurgia (FESS) se refratária\n• Sem pólipos: ATB prolongado + corticoide nasal + lavagem\n• TC de seios paranasais (padrão para avaliação)\n• Investigar: alergia, imunodeficiência, fibrose cística, discinesia ciliar", category: "otorrino", tags: ["sinusite", "aguda", "crônica"] },
  { id: "fc-orl-09", front: "Paralisia facial periférica (Bell) — tratamento?", back: "Diagnóstico: paralisia facial unilateral COMPLETA (fronte + inferior). Início agudo (pico 48-72h).\n\nExcluir: AVC (poupa fronte), otite média, Ramsay Hunt (vesículas auriculares), tumor de parótida, Lyme.\n\nTratamento (iniciar < 72h):\n1. Prednisona 1mg/kg/dia por 7 dias + desmame\n2. Valaciclovir 1g 3x/dia por 7 dias (controverso, considerar se grave)\n3. Proteção ocular: lágrima artificial + pomada + oclusão noturna\n\nPrognóstico: 85% recuperação completa em 3-6 meses.\nHouse-Brackmann: escala de gravidade (I-VI).", category: "otorrino", tags: ["paralisia bell", "facial", "house-brackmann"] },
  { id: "fc-orl-10", front: "Laringotraqueíte aguda (crupe) — classificação e tratamento?", back: "Causa: parainfluenza (75%). Idade: 6 meses a 6 anos. Tosse ladrante, estridor inspiratório, rouquidão.\n\nRX: sinal da torre/ponta de lápis (estenose subglótica).\n\nClassificação (Westley):\nLeve: estridor apenas ao chorar → Dexametasona 0.6mg/kg VO dose única\nModerada: estridor em repouso → Dexametasona + Nebulização com adrenalina 0.5ml/kg (máx 5ml) L-adrenalina 1:1000\nGrave: estridor + tiragem + agitação/letargia → Dexametasona + Adrenalina NBI + considerar IOT\n\nObservar 4h após adrenalina (efeito rebote).", category: "otorrino", tags: ["crupe", "laringotraqueíte", "estridor"] },
  { id: "fc-orl-11", front: "Doença de Ménière — diagnóstico e tratamento?", back: "Tríade clássica: vertigem episódica (20min-12h) + hipoacusia neurossensorial flutuante (baixas frequências) + zumbido + plenitude auricular.\n\nCritérios diagnósticos: ≥ 2 episódios de vertigem (20min-12h) + hipoacusia neurossensorial documentada + zumbido/plenitude flutuante.\n\nTratamento:\n• Crise: supressores vestibulares (meclizina, dimenidrinato)\n• Manutenção: dieta hipossódica (< 2g/dia), betaistina 16-24mg 3x/dia, diuréticos (hidroclorotiazida)\n• Refratário: injeção intratimpânica de gentamicina ou corticoide\n• Cirúrgico: descompressão do saco endolinfático", category: "otorrino", tags: ["ménière", "vertigem", "hipoacusia"] },
  { id: "fc-orl-12", front: "Angina de Ludwig — diagnóstico e tratamento de emergência?", back: "Infecção do espaço submandibular bilateral + sublingual. Origem: infecção dentária (70-90%).\n\nClínica: edema submandibular bilateral firme ('pescoço de touro'), elevação do assoalho da boca, trismo, disfagia, sialorreia, estridor.\n\nRISCO: obstrução de via aérea (principal causa de morte).\n\nTratamento:\n1. Via aérea: IOT precoce (pode necessitar fibroscopia/traqueostomia)\n2. ATB IV: Ampicilina-sulbactam ou Clindamicina + Ceftriaxone\n3. Drenagem cirúrgica se coleção\n4. Corticoide: Dexametasona IV (reduz edema)", category: "otorrino", tags: ["ludwig", "submandibular", "via aérea"] },
  { id: "fc-orl-13", front: "Apneia obstrutiva do sono — diagnóstico e tratamento?", back: "Sintomas: ronco, apneias testemunhadas, sonolência diurna excessiva (Epworth ≥ 10), cefaleia matinal.\n\nDiagnóstico: polissonografia (padrão-ouro).\nIAH (índice apneia-hipopneia):\n• Leve: 5-14/h\n• Moderada: 15-29/h\n• Grave: ≥ 30/h\n\nTratamento:\n• Leve: perda de peso, higiene do sono, posição lateral\n• Moderada-grave: CPAP (1ª linha)\n• Dispositivo de avanço mandibular (leve-moderada)\n• Cirúrgico: uvulopalatofaringoplastia (selecionados)\n• Crianças: adenoamigdalectomia (1ª linha)", category: "otorrino", tags: ["saos", "cpap", "polissonografia"] },

  // ========== NEFROLOGIA AVANÇADA ==========
  { id: "fc-nefro-04", front: "Glomerulonefrites — classificação por síndrome clínica?", back: "Síndrome nefrítica: hematúria dismórfica, proteinúria subnefrótica, HAS, edema, oligúria. Ex: GNPE, nefrite lúpica, IgA.\n\nSíndrome nefrótica: proteinúria > 3.5g/dia, hipoalbuminemia, edema, hiperlipidemia. Ex: lesão mínima (crianças), GESF, membranosa.\n\nGNRP (crescêntica): perda rápida de função renal. Tipos:\n• I: anti-MBG (Goodpasture)\n• II: imunocomplexos (lúpus, GNPE)\n• III: pauci-imune (ANCA — Wegener, PAM)", category: "nefrologia", tags: ["glomerulonefrite", "nefrítica", "nefrótica"] },
  { id: "fc-nefro-05", front: "Distúrbios do sódio — hiponatremia aguda sintomática?", back: "Definição: Na < 135 mEq/L. Aguda: < 48h. Sintomática: cefaleia, náuseas, convulsão, coma.\n\nTratamento de EMERGÊNCIA:\n• NaCl 3% (513 mEq/L): 100-150ml em bolus IV em 10-20min\n• Repetir até 2x se sintomas persistirem\n• Meta: elevar Na 4-6 mEq/L nas primeiras 6h\n• Limite: NÃO elevar > 8-10 mEq/L em 24h (risco de desmielinização osmótica/mielinólise pontina)\n\nHiponatremia crônica assintomática: restrição hídrica + tratar causa.", category: "nefrologia", tags: ["hiponatremia", "sódio", "nacl 3%"] },
  { id: "fc-nefro-06", front: "Hipercalemia — ECG e tratamento escalonado?", back: "ECG progressivo:\n1. Onda T apiculada (> 5.5)\n2. Alargamento de QRS (> 6.5)\n3. Perda de onda P (> 7.0)\n4. Onda sinusoidal → FV/assistolia (> 8.0)\n\nTratamento:\n1. Gluconato de Ca 10% 10ml IV em 3min (estabiliza membrana) — se ECG alterado\n2. Insulina regular 10UI + Glicose 50% 50ml IV (shift — 15-30min)\n3. Beta-2 agonista (salbutamol 10-20mg NBI)\n4. Bicarbonato de Na 8.4% (se acidose)\n5. Furosemida 40-80mg IV (eliminação)\n6. Sorcal (poliestirenossulfonato) 15-30g VO\n7. Diálise se refratário", category: "nefrologia", tags: ["hipercalemia", "potássio", "ecg"] },
  { id: "fc-nefro-07", front: "Nefropatia diabética — estadiamento e nefroprevenção?", back: "Estágios:\n1. Hiperfiltração (TFG elevada)\n2. Normoalbuminúria\n3. Microalbuminúria (30-300mg/dia) — reversível!\n4. Macroalbuminúria (> 300mg/dia)\n5. IRC terminal (diálise)\n\nNefroprevenção:\n• IECA ou BRA: 1ª linha (reduzem proteinúria e progressão)\n• SGLT2i (dapagliflozina, empagliflozina): benefício renal comprovado (DAPA-CKD, CREDENCE)\n• Finerenona: antagonista mineralocorticoide não-esteroidal\n• HbA1c < 7%, PA < 130/80, LDL < 100\n• Rastreio anual: albumina/creatinina urinária + TFG", category: "nefrologia", tags: ["nefropatia diabética", "sglt2", "nefroprevenção"] },
  { id: "fc-nefro-08", front: "Acidose tubular renal — tipos e diferenças?", back: "Tipo 1 (distal): não consegue secretar H+. pH urinário > 5.5, hipocalemia, nefrocalcinose/nefrolitíase. Causas: Sjögren, LES, anfotericina.\n\nTipo 2 (proximal): não reabsorve HCO₃. pH urinário variável, hipocalemia, síndrome de Fanconi. Causas: mieloma, acetazolamida.\n\nTipo 4 (hipoaldosteronismo): HIPERcalemia, acidose leve. pH urinário < 5.5. Causas: DM (mais comum), IECA/BRA, espironolactona, insuficiência adrenal.\n\nTodas: acidose metabólica hiperclorêmica com AG normal.", category: "nefrologia", tags: ["acidose tubular", "atr", "hiperclorêmica"] },
  { id: "fc-nefro-09", front: "Doença renal policística autossômica dominante — manejo?", back: "Gene: PKD1 (85%, mais grave) e PKD2. Herança autossômica dominante.\n\nClínica: cistos renais bilaterais, HAS precoce, hematúria, dor lombar, nefrolitíase, ITU de cistos, cistos hepáticos (50%), aneurisma intracraniano (5-10%).\n\nDiagnóstico: USG (critérios por idade/gene).\n\nManejo:\n• Controle PA agressivo (IECA/BRA, meta < 110/75 se < 50 anos)\n• Tolvaptana: retarda crescimento renal em casos selecionados (TFG > 25)\n• Rastreio de aneurisma: RM cerebral se história familiar positiva\n• Evitar cafeína (crescimento de cistos)\n• Diálise/transplante se IRC terminal", category: "nefrologia", tags: ["policística", "drpad", "tolvaptana"] },
  { id: "fc-nefro-10", front: "Síndrome hepatorrenal — diagnóstico e tratamento?", back: "Definição: IRA funcional em cirróticos com ascite, sem causa parenquimatosa identificável.\n\nCritérios: cirrose + ascite + Cr > 1.5mg/dL + sem melhora após 2 dias de expansão com albumina (1g/kg) + sem choque + sem nefrotóxicos + sem doença parenquimatosa renal.\n\nTipo 1 (AKI): Cr duplica em < 2 semanas. Grave, sobrevida sem tratamento ~2 semanas.\nTipo 2: mais indolente, associado a ascite refratária.\n\nTratamento:\n• Terlipressina + Albumina (1ª linha)\n• Noradrenalina + Albumina (alternativa)\n• TIPS em selecionados\n• Transplante hepático (definitivo)", category: "nefrologia", tags: ["hepatorrenal", "terlipressina", "cirrose"] },

  // ========== GERIATRIA ==========
  { id: "fc-geri-01", front: "Avaliação geriátrica ampla (AGA) — domínios?", back: "1. Funcionalidade: AVDs básicas (Katz) + AVDs instrumentais (Lawton-Brody)\n2. Cognição: Mini-Exame do Estado Mental (MEEM), MoCA, teste do relógio\n3. Humor: Escala de Depressão Geriátrica (GDS-15 ou GDS-5)\n4. Mobilidade: Timed Up and Go (TUG), velocidade de marcha, equilíbrio\n5. Nutrição: MNA (Mini Nutritional Assessment), IMC, albumina\n6. Risco de quedas: histórico, TUG > 12s, Tinetti\n7. Social: suporte familiar, cuidador, institucionalização\n8. Polifarmácia: critérios de Beers, START/STOPP\n\nAGA guia o plano de cuidado individualizado.", category: "geriatria", tags: ["aga", "funcionalidade", "avaliação"] },
  { id: "fc-geri-02", front: "Delirium — diagnóstico (CAM) e tratamento?", back: "CAM (Confusion Assessment Method):\n1. Início agudo + flutuação (obrigatório)\n2. Desatenção (obrigatório)\n3. Pensamento desorganizado OU\n4. Alteração do nível de consciência\n\n(1+2) + (3 ou 4) = delirium\n\nSubtipos: hiperativo (25%), hipoativo (25% — pior prognóstico, subdiagnosticado), misto (50%).\n\nTratamento: TRATAR A CAUSA (infecção, medicamento, dor, retenção urinária, constipação, DHE).\nMedidas não-farmacológicas: orientação, luz natural, óculos/aparelho auditivo, mobilização.\nHaloperidol 0.5-1mg VO/IM apenas se agitação grave com risco.", category: "geriatria", tags: ["delirium", "cam", "hipoativo"] },
  { id: "fc-geri-03", front: "Critérios de Beers — medicamentos potencialmente inapropriados para idosos?", back: "Evitar em idosos (alto risco de eventos adversos):\n• BZD de longa ação: diazepam, clonazepam (quedas, sedação)\n• Anticolinérgicos: amitriptilina, hidroxizina, prometazina\n• AINEs cronicamente: risco GI e renal\n• Metoclopramida > 12 semanas: parkinsonismo\n• Glibenclamida: hipoglicemia prolongada\n• Anti-histamínicos 1ª geração: sedação, confusão\n• Alfa-bloqueadores para HAS: hipotensão ortostática\n• Digoxina > 0.125mg/dia\n\nPreferir: paracetamol, ISRS, mirtazapina, BZD curta ação se necessário.", category: "geriatria", tags: ["beers", "polifarmácia", "inapropriado"] },
  { id: "fc-geri-04", front: "Síndrome de fragilidade — critérios de Fried?", back: "Fenótipo de fragilidade (≥ 3 = frágil, 1-2 = pré-frágil):\n1. Perda de peso não intencional (> 4.5kg ou 5% em 1 ano)\n2. Exaustão autorreferida\n3. Fraqueza (força de preensão palmar baixa)\n4. Lentidão (velocidade de marcha reduzida)\n5. Baixo nível de atividade física\n\nFragilidade ≠ incapacidade ≠ comorbidade (podem coexistir).\n\nManejo: exercício resistido (mais eficaz), nutrição proteica (1.2-1.5g/kg/dia), vitamina D, revisão de polifarmácia, suporte social.", category: "geriatria", tags: ["fragilidade", "fried", "sarcopenia"] },
  { id: "fc-geri-05", front: "Demência — tipos e diferenças clínicas?", back: "Alzheimer (60-70%): memória episódica, início insidioso, progressão gradual. Biomarcadores: amiloide/tau.\n\nVascular (15-20%): progressão em degraus, fatores de risco CV, sinais focais.\n\nCorpos de Lewy: flutuação cognitiva, alucinações visuais precoces, parkinsonismo, sensibilidade a neurolépticos (CONTRAINDICADOS!).\n\nFrontotemporal: personalidade/comportamento precoce OU afasia progressiva primária, < 65 anos.\n\nReversíveis (5%): hipotireoidismo, déficit B12, hidrocefalia de pressão normal (demência + ataxia + incontinência), neurossífilis.", category: "geriatria", tags: ["demência", "alzheimer", "lewy"] },
  { id: "fc-geri-06", front: "Prevenção de quedas em idosos — avaliação e intervenções?", back: "Avaliação:\n• Histórico de quedas (≥ 2 no último ano = alto risco)\n• TUG > 12 segundos\n• Tinetti < 19 pontos\n• Teste de Romberg\n• Acuidade visual\n• Hipotensão ortostática\n• Revisão de medicamentos (BZD, anti-hipertensivos, psicotrópicos)\n\nIntervenções com evidência:\n• Exercício multicomponente (equilíbrio + força): TAI CHI\n• Correção visual\n• Vitamina D 800-1000 UI/dia\n• Revisão/retirada de medicamentos\n• Adaptação ambiental (barras, iluminação, tapetes)\n• Calçado adequado", category: "geriatria", tags: ["quedas", "prevenção", "tug"] },
  { id: "fc-geri-07", front: "Imobilismo — complicações e prevenção?", back: "Complicações sistêmicas:\n• Pele: úlcera de pressão (Braden < 12 = alto risco)\n• Muscular: sarcopenia, contraturas (perda de 1-3% de força/dia)\n• Ósseo: osteoporose, fraturas\n• Cardiovascular: TVP, TEP, hipotensão ortostática\n• Respiratório: atelectasia, pneumonia\n• GI: constipação, inapetência\n• Urinário: ITU, retenção\n• Cognitivo: delirium, depressão\n\nPrevenção:\n• Mobilização PRECOCE (< 24h se possível)\n• Mudança de decúbito a cada 2h\n• Profilaxia de TVP (enoxaparina)\n• Colchão pneumático se Braden baixo", category: "geriatria", tags: ["imobilismo", "úlcera pressão", "braden"] },
  { id: "fc-geri-08", front: "Cuidados paliativos — indicações e princípios?", back: "Indicações: doença ameaçadora de vida, independente do prognóstico temporal. Iniciar JUNTO com tratamento curativo.\n\nPrincípios (OMS):\n• Alívio da dor e outros sintomas\n• Afirmar a vida e a morte como processo natural\n• Não apressar nem adiar a morte\n• Integrar aspectos psicossociais e espirituais\n• Suporte à família (incluindo luto)\n\nEscala funcional: PPS (Palliative Performance Scale).\nPPS ≤ 30%: provável prognóstico < 3 meses.\n\nEscada da OMS para dor:\n1. Não-opioide (paracetamol, dipirona)\n2. Opioide fraco (codeína, tramadol)\n3. Opioide forte (morfina, metadona, fentanil)", category: "geriatria", tags: ["paliativos", "pps", "dor"] },
  { id: "fc-geri-09", front: "Polifarmácia — desprescrição racional?", back: "Polifarmácia: ≥ 5 medicamentos de uso crônico.\n\nProtocolo de desprescrição:\n1. Listar TODOS os medicamentos (incluindo OTC, fitoterápicos)\n2. Identificar indicação atual de cada um\n3. Avaliar risco/benefício individual\n4. Priorizar retirada: sem indicação > alto risco > duplicidade\n5. Reduzir gradualmente (1 de cada vez, monitorar 2-4 semanas)\n\nFerramentas:\n• Beers (evitar em idosos)\n• STOPP (parar se inadequado)\n• START (iniciar se indicado e ausente)\n• MAI (Medication Appropriateness Index)\n\nRisco de cascata de prescrição: EA → diagnóstico errado → novo medicamento.", category: "geriatria", tags: ["polifarmácia", "desprescrição", "stopp-start"] },
  { id: "fc-geri-10", front: "Incontinência urinária no idoso — tipos e tratamento?", back: "Esforço: perda ao tossir/espirrar. Fraqueza do assoalho pélvico.\nTto: exercícios de Kegel, duloxetina, cirurgia (sling).\n\nUrgência: desejo súbito imperioso. Hiperatividade do detrusor.\nTto: treinamento vesical, anticolinérgicos (oxibutinina — evitar em idosos! preferir mirabegrona), toxina botulínica.\n\nTransbordamento: retenção crônica com gotejamento. HPB, neuropatia.\nTto: alfa-bloqueador (tansulosina), cateterismo.\n\nFuncional: incapacidade de chegar ao banheiro. Demência, imobilidade.\nTto: adaptações, cuidador, fraldas.\n\nMnemônico DIAPPERS: Delirium, Infecção, Atrófica, Psicológica, Pharma, Endócrina, Restrição, Stool.", category: "geriatria", tags: ["incontinência urinária", "urgência", "diappers"] },
  { id: "fc-geri-11", front: "Osteoporose — diagnóstico e tratamento?", back: "Diagnóstico: DXA (densitometria).\nT-score:\n• > -1.0: normal\n• -1.0 a -2.5: osteopenia\n• ≤ -2.5: osteoporose\n• ≤ -2.5 + fratura: osteoporose estabelecida\n\nFRAAX: estima risco de fratura em 10 anos.\n\nTratamento:\n• Cálcio 1000-1200mg/dia + Vitamina D 800-1000UI/dia\n• Bisfosfonatos (1ª linha): alendronato 70mg/sem, ácido zoledrônico 5mg IV/ano\n• Denosumabe: anti-RANKL SC semestral (alternativa)\n• Teriparatida: análogo de PTH (osteoporose grave)\n• Romosozumabe: anti-esclerostina (novidade)\n\nPrevenção de fraturas: exercício + prevenção de quedas.", category: "geriatria", tags: ["osteoporose", "dxa", "bisfosfonato"] },
  { id: "fc-geri-12", front: "Depressão no idoso — particularidades?", back: "Prevalência: 15-20% em idosos na comunidade. Subdiagnosticada.\n\nParticularidades:\n• Queixas somáticas predominam sobre humor triste\n• Pseudodemência depressiva (diferencia de demência verdadeira)\n• Risco de suicídio mais alto que em jovens\n• Depressão vascular (lesões de substância branca)\n\nRastreio: GDS-15 (≥ 5 pontos) ou PHQ-2/PHQ-9.\n\nTratamento:\n• ISRS: sertralina, escitalopram (1ª escolha)\n• Mirtazapina: se insônia/inapetência\n• Duloxetina: se dor crônica associada\n• EVITAR: tricíclicos (anticolinérgicos), fluoxetina (interações)\n• Associar psicoterapia (TCC)", category: "geriatria", tags: ["depressão", "idoso", "gds"] },
  { id: "fc-geri-13", front: "Hidrocefalia de pressão normal — tríade e diagnóstico?", back: "Tríade de Hakim-Adams:\n1. Demência (subcortical — lentificação, apatia)\n2. Ataxia da marcha (magnética — passos curtos, base alargada, pés 'grudados no chão')\n3. Incontinência urinária\n\nA MARCHA é o primeiro sintoma e o que mais responde ao tratamento.\n\nDiagnóstico:\n• TC/RM: ventriculomegalia desproporcional aos sulcos\n• Índice de Evans > 0.3 (razão dos cornos frontais/diâmetro craniano)\n• Tap test (punção lombar de alívio — 30-50ml): melhora da marcha em 24-48h\n\nTratamento definitivo: derivação ventriculoperitoneal (DVP).", category: "geriatria", tags: ["hidrocefalia", "hakim-adams", "dvp"] },
  ...flashcardsExtraImport,
];
